-- Poems batch 183
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('734c9bc5-1829-4fa4-9826-548f6cbfe642','昌甫詩來言九日是悼亡之日因答和及紫芝是日過城下  其二','韓淲','宋','宋诗','song-poetry','','[]','紫芝九日上杭都，溪館經從說大蘇。',32,'全唐诗/poet.song.177000.json','["紫芝九日上杭都，溪館經從說大蘇。", "摇落風霜爲搔首，病餘真是我非夫。"]'),
('3438ff50-b05a-486d-9c27-7871e232e5e2','昌甫詩來言九日是悼亡之日因答和及紫芝是日過城下  其三','韓淲','宋','宋诗','song-poetry','','[]','佳辰人物本難俱，事事雖非景不殊。',32,'全唐诗/poet.song.177000.json','["佳辰人物本難俱，事事雖非景不殊。", "君既悼亡應感舊，細看那復嗅茱萸。"]'),
('2109c04e-4880-49cc-b217-f3674babf768','昌甫詩來言九日是悼亡之日因答和及紫芝是日過城下  其四','韓淲','宋','宋诗','song-poetry','','[]','黄落山川亦變衰，平生高李吹臺詩。',32,'全唐诗/poet.song.177000.json','["黄落山川亦變衰，平生高李吹臺詩。", "秋來季月谿南路，獨往空歌宋玉悲。"]'),
('27d1540b-5947-4e1e-b14a-fef99fac5e0a','九日范伯升惠詩連伯玉丈有和句皆道先公平昔登高事感而次韵  其一','韓淲','宋','宋诗','song-poetry','','[]','詩來增我思親念，愁對秋山氣象高。',32,'全唐诗/poet.song.178000.json','["詩來增我思親念，愁對秋山氣象高。", "糝糝黄花驚節物，東籬徒有鬢蕭騷。"]'),
('975ede01-5225-4a0f-bbbd-bf34b1c54158','九日范伯升惠詩連伯玉丈有和句皆道先公平昔登高事感而次韵  其二','韓淲','宋','宋诗','song-poetry','','[]','塵土裝懷不可論，傷心夏凊與冬溫。',32,'全唐诗/poet.song.178000.json','["塵土裝懷不可論，傷心夏凊與冬溫。", "西風南澗蕭蕭竹，猶有范翁時到門。"]'),
('5000d46e-4f8e-42cc-adf5-5d114f103f34','次韵昌甫所賦癩可瘦權且言去歲到白鹿洞  其一','韓淲','宋','宋诗','song-poetry','','[]','踏雪尋僧已是詩，更將書冊試同披。',32,'全唐诗/poet.song.178000.json','["踏雪尋僧已是詩，更將書冊試同披。", "名高直隠江西社，五字非君熟和斯。"]'),
('68d3d2d1-6d00-492f-8176-699d2e2519fa','次韵昌甫所賦癩可瘦權且言去歲到白鹿洞  其二','韓淲','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','當年權可氣橫秋，此日匡山亦雪不。',32,'全唐诗/poet.song.178000.json','["當年權可氣橫秋，此日匡山亦雪不。", "莫恨禪牀人寂寂，可論書院鹿呦呦。"]'),
('05f68706-0b60-4f04-8bba-ea9c16ea162b','李季章參政寄近作絕句次韵答之  其一','韓淲','宋','宋诗','song-poetry','','[]','誰家綠展窗前葉，何物清成池上花。',32,'全唐诗/poet.song.178000.json','["誰家綠展窗前葉，何物清成池上花。", "嘆息陶斯爲模寫，要須隨興寄無涯。"]'),
('d470af22-2bea-408e-ae12-4c0d80bbde7f','李季章參政寄近作絕句次韵答之  其二','韓淲','宋','宋诗','song-poetry','','[]','華髮差差從滿顛，形神纔釋自蹁躚。',32,'全唐诗/poet.song.178000.json','["華髮差差從滿顛，形神纔釋自蹁躚。", "角巾東路渾常事，便駕柴車亦可憐。"]'),
('59ee7322-db6a-4659-b3ec-a9495ae8ed05','李季章參政寄近作絕句次韵答之  其三','韓淲','宋','宋诗','song-poetry','','[]','秋深剩有十分凉，好理平生書傳香。',32,'全唐诗/poet.song.178000.json','["秋深剩有十分凉，好理平生書傳香。", "見說江西多勝士，吟成風雨近重陽。"]'),
('675440aa-8569-4936-ba6b-da55e7b0d5e3','李季章參政寄近作絕句次韵答之  其四','韓淲','宋','宋诗','song-poetry','','[]','得將膠擾一身藏，吳是他鄉蜀故鄉。',32,'全唐诗/poet.song.178000.json','["得將膠擾一身藏，吳是他鄉蜀故鄉。", "從昔衰榮無定在，山林鐘鼎兩俱長。"]'),
('0c8040aa-0017-4637-97a6-50d878b2564c','李季章參政寄近作絕句次韵答之  其五','韓淲','宋','宋诗','song-poetry','','[]','禪門底用金仙偈，道室空多玉笈書。',32,'全唐诗/poet.song.178000.json','["禪門底用金仙偈，道室空多玉笈書。", "知我者希斯我貴，身心如此可踟躇。"]'),
('fb8a732c-4e32-47b0-92b0-c5e3b9229367','李季章參政寄近作絕句次韵答之  其六','韓淲','宋','宋诗','song-poetry','','[]','家食何如祿萬鍾，夢回珂轡響玲瓏。',32,'全唐诗/poet.song.178000.json','["家食何如祿萬鍾，夢回珂轡響玲瓏。", "書生習氣初無恙，只怕勳名不貸公。"]'),
('ae71ae7d-9c5a-40a3-a645-f07eec5e7fdb','次韵張令郊行  其一','韓淲','宋','宋诗','song-poetry','','[]','連朝晴日破層陰，下澤翩翩興愈深。',32,'全唐诗/poet.song.178000.json','["連朝晴日破層陰，下澤翩翩興愈深。", "水際風翻沽酒旆，靜看飛鳥過平林。"]'),
('bf14d15a-2a71-4f22-95e7-159d04157d49','次韵張令郊行  其二','韓淲','宋','宋诗','song-poetry','','[]','不須萬里羨侯封，且把千詩一撫松。',32,'全唐诗/poet.song.178000.json','["不須萬里羨侯封，且把千詩一撫松。", "野步何人知此意，仙家寒露濕芙蓉。"]'),
('75388b07-f4e3-4c09-82ba-b22c15971bdf','次韵張令郊行  其三','韓淲','宋','宋诗','song-poetry','','[]','尋詩得酒坐閒亭，秋到騷人獨用情。',32,'全唐诗/poet.song.178000.json','["尋詩得酒坐閒亭，秋到騷人獨用情。", "猶有黄花看著眼，悠然風味憶淵明。"]'),
('d7757ef3-05aa-49fb-86c2-941e30b5cf5b','次韵張令郊行  其四','韓淲','宋','宋诗','song-poetry','','[]','鬢絲禪榻紙窗西，柏子煙中落景遲。',32,'全唐诗/poet.song.178000.json','["鬢絲禪榻紙窗西，柏子煙中落景遲。", "莫問少年塗抹事，病餘那復解題詩。"]'),
('8cc2102c-a784-40db-b435-b09f24235e0f','次韵張令郊行  其五','韓淲','宋','宋诗','song-poetry','','[]','薄寒侵曉露華明，不信人間有許清。',32,'全唐诗/poet.song.178000.json','["薄寒侵曉露華明，不信人間有許清。", "行遍西郊草堂外，老懷渾不負秋晴。"]'),
('5003018f-8570-4afd-825d-e58ac5883769','元立留詩二首因次韵  其一','韓淲','宋','宋诗','song-poetry','','[]','少下歸帆上石梯，高風雖在後人迷。',32,'全唐诗/poet.song.178000.json','["少下歸帆上石梯，高風雖在後人迷。", "倦懷冷坐客星閣，煙雨漫山覓舊題。"]'),
('aae52fba-e9d7-4612-9e1b-6be35bbb628d','元立留詩二首因次韵  其二','韓淲','宋','宋诗','song-poetry','','[]','孟郊有句散愁端，墨妙猶能待我看。',32,'全唐诗/poet.song.178000.json','["孟郊有句散愁端，墨妙猶能待我看。", "試問新秋能幾日，欄干一葉已吹寒。"]'),
('968e4936-52f8-4748-a080-ab856db5ea54','文叔樓居次韵戲之','韓淲','宋','宋诗','song-poetry','','[]','行藏知在倚樓間，雨際煙巒接九關。',32,'全唐诗/poet.song.178000.json','["行藏知在倚樓間，雨際煙巒接九關。", "著脚既高心自遠，問言何似嶽前山。"]'),
('d20cfd7e-9989-4fa9-8863-e7849bbfbf22','樓外新綠成陰片月已上','韓淲','宋','宋诗','song-poetry','','[]','隔簾花過葉初青，一段清和倚畫屏。',32,'全唐诗/poet.song.178000.json','["隔簾花過葉初青，一段清和倚畫屏。", "已是春風生晝寂，小樓新月更亭亭。"]'),
('ac0be489-cc36-4e5d-87bb-826c701ae9f1','次韵郭中','韓淲','宋','宋诗','song-poetry','','[]','常恐塵埃滿面顔，水邊門戶喜常關。',32,'全唐诗/poet.song.178000.json','["常恐塵埃滿面顔，水邊門戶喜常關。", "蒼筤亭上南屏下，天遣幽人入座前。"]'),
('e6841d48-b9c1-4782-95b7-01e534cd04b8','次韵  其一','韓淲','宋','宋诗','song-poetry','','[]','菊花開處即重陽，常憶蘇仙共酒觴。',32,'全唐诗/poet.song.178000.json','["菊花開處即重陽，常憶蘇仙共酒觴。", "霜後擷香尤可玩，喚回佳致有篇章。"]'),
('2e68782b-bb96-4c7a-96c7-8a368016381f','次韵  其二','韓淲','宋','宋诗','song-poetry','','[]','秋到黄花强自寬，琴堂猶得往來閒。',32,'全唐诗/poet.song.178000.json','["秋到黄花强自寬，琴堂猶得往來閒。", "世情原與詩情背，只許閒人老眼看。"]'),
('7f0e5a18-ff61-4164-b086-6b59588890ed','次韵  其三','韓淲','宋','宋诗','song-poetry','','[]','道愛堂深風滿林，一由華髮半欺簪。',32,'全唐诗/poet.song.178000.json','["道愛堂深風滿林，一由華髮半欺簪。", "主人記取從容意，三客無他只苦吟。"]'),
('cbd01591-d35a-4eaa-99e3-59bfb744f3a4','次韵周次公五日','韓淲','宋','宋诗','song-poetry','','[]','溪頭拍浪鼓喧天，驚動山翁一覺眠。',32,'全唐诗/poet.song.178000.json','["溪頭拍浪鼓喧天，驚動山翁一覺眠。", "且喜和番征戰息，兒郎贏得鬭龍船。"]'),
('cf7b3376-8094-4613-b1b0-6f195286e91d','次韵周次公  其一','韓淲','宋','宋诗','song-poetry','','[]','高隠春山意頗濃，眼明四海有無中。',32,'全唐诗/poet.song.178000.json','["高隠春山意頗濃，眼明四海有無中。", "憑誰喚取爲時用，橫带東華醉軟紅。"]'),
('4f1ea67f-846b-4de1-88be-038c45bc53a4','次韵周次公  其二','韓淲','宋','宋诗','song-poetry','','[]','自覺頹然已白頭，塵塵何地不周流。',32,'全唐诗/poet.song.178000.json','["自覺頹然已白頭，塵塵何地不周流。", "從渠膠擾蝸牛角，連雨清寒正麥秋。"]'),
('bf1fdaa7-7edc-41cf-be35-af285622e16b','次韵  其一','韓淲','宋','宋诗','song-poetry','','[]','山田喜雨厭晴霞，想見汙邪欲滿車。',32,'全唐诗/poet.song.178000.json','["山田喜雨厭晴霞，想見汙邪欲滿車。", "客裏從今無貴米，飯餘贏得去煎茶。"]'),
('59044e9b-eb39-4a86-9f77-328e2469bf6c','次韵  其二','韓淲','宋','宋诗','song-poetry','','[]','十日山頭有雨雲，小樓凉意滿紗巾。',32,'全唐诗/poet.song.178000.json','["十日山頭有雨雲，小樓凉意滿紗巾。", "清湖一带水常綠，空映往來行路人。"]'),
('235deec8-92fb-415b-b200-78cdaaa3cce8','次韵  其三','韓淲','宋','宋诗','song-poetry','','[]','青山常對我軒窗，更有澄江作小堂。',32,'全唐诗/poet.song.178000.json','["青山常對我軒窗，更有澄江作小堂。", "今日塵埃無自奈，且乘凉雨卧行牀。"]'),
('b5479242-fe66-4bc0-a386-875a79962476','次韵昌甫  其一','韓淲','宋','宋诗','song-poetry','','[]','雲白天青懷玉山，森如束筍杳難攀。',32,'全唐诗/poet.song.178000.json','["雲白天青懷玉山，森如束筍杳難攀。", "章泉章丘不百里，是二士者居其間。"]'),
('2b336532-f7ea-4cfd-98db-9fa08940c430','次韵昌甫  其二','韓淲','宋','宋诗','song-poetry','','[]','雲白天青懷玉山，應真留影與僧閒。',32,'全唐诗/poet.song.178000.json','["雲白天青懷玉山，應真留影與僧閒。", "安得務農息戰鬭，老身長子從鬢斑。"]'),
('fe2c6760-7809-4c3f-91b3-1f44b16fd20d','二十二日次韵徐子融所寄','韓淲','宋','宋诗','song-poetry','','[]','近年交友已相安，只要山林保歲寒。',32,'全唐诗/poet.song.178000.json','["近年交友已相安，只要山林保歲寒。", "珍重茅齋徐處士，有詩猶許寄來看。"]'),
('9bc37f02-243f-44bc-b792-60b39df75b9e','次韵劉解元','韓淲','宋','宋诗','song-poetry','','["\u897f\u6e56"]','天寒歲晚山黄落，只擬西湖可探梅。',32,'全唐诗/poet.song.178000.json','["天寒歲晚山黄落，只擬西湖可探梅。", "霜重雪深渾不管，一枝青淺爲誰開。"]'),
('6aea590a-0b24-43cd-bb87-ffdce21daf6e','和推官  其一','韓淲','宋','宋诗','song-poetry','','[]','雨餘千里得安眠，凉翼條苗綠滿川。',32,'全唐诗/poet.song.178000.json','["雨餘千里得安眠，凉翼條苗綠滿川。", "郡幕有賢時自熟，不勞水利問農田。"]'),
('8874207e-3cb1-410b-9a7c-94c81031f2d7','和推官  其二','韓淲','宋','宋诗','song-poetry','','[]','文字工夫勝鏤冰，眼邊猶信耳邊聲。',32,'全唐诗/poet.song.178000.json','["文字工夫勝鏤冰，眼邊猶信耳邊聲。", "暗中摸索曹劉在，嘗鼎酸鹹不待烹。"]'),
('49456613-9cc1-4420-bdee-1c1045cb7914','和推官  其三','韓淲','宋','宋诗','song-poetry','','[]','乘凉一雨過城扉，促膝應看玉屑飛。',32,'全唐诗/poet.song.178000.json','["乘凉一雨過城扉，促膝應看玉屑飛。", "名下無虛真雅士，清談可飽弗憂饑。"]'),
('05b2c03e-1acc-4e75-b032-c1d7eda89371','和推官  其四','韓淲','宋','宋诗','song-poetry','','[]','雲連山色晚青蒼，雨激平疇土氣香。',32,'全唐诗/poet.song.178000.json','["雲連山色晚青蒼，雨激平疇土氣香。", "清入斷畦纔汩沒，黄流別港又瀰茫。"]'),
('ff32fcf4-1243-43e5-9283-853c5a9a7bfb','和推官  其五','韓淲','宋','宋诗','song-poetry','','[]','得詩得雨百憂寬，散髮林間久不冠。',32,'全唐诗/poet.song.178000.json','["得詩得雨百憂寬，散髮林間久不冠。", "讀盡名章轉搔首，靜看簷溜落驚湍。"]'),
('4f26412f-6097-4bb8-a7bf-91359c9e433b','次韵吳推官  其一','韓淲','宋','宋诗','song-poetry','','[]','樟下臨岐樹色分，風沙吹日暗車塵。',32,'全唐诗/poet.song.178000.json','["樟下臨岐樹色分，風沙吹日暗車塵。", "尋思何地無幽興，不在山林只在人。"]'),
('b289f382-5561-4216-8165-19efb1b71433','次韵吳推官  其二','韓淲','宋','宋诗','song-poetry','','[]','投老寬閒寂寞濱，將身隠兮又何文。',32,'全唐诗/poet.song.178000.json','["投老寬閒寂寞濱，將身隠兮又何文。", "暫時相商相徵逐，留與江東日暮雲。"]'),
('7f66a397-d623-4185-a4c3-91671fa986d4','次韵吳推官  其三','韓淲','宋','宋诗','song-poetry','','[]','一片溪流一片山，世氛元自不相關。',32,'全唐诗/poet.song.178000.json','["一片溪流一片山，世氛元自不相關。", "松溪直上山頭洞，僧亦何能識我閒。"]'),
('8566cdc4-3a13-4ed9-80ed-45bf1a80391a','次韵吳推官  其四','韓淲','宋','宋诗','song-poetry','','[]','因酒從容意已仙，白沙翠竹記同船。',32,'全唐诗/poet.song.178000.json','["因酒從容意已仙，白沙翠竹記同船。", "停杯更在斜陽外，此話他年儘可傳。"]'),
('a18d7b80-97e8-4d22-ae8a-3b28636c0dd3','次韵吳推官  其五','韓淲','宋','宋诗','song-poetry','','[]','十日之間我欲回，仍於真隠一尊開。',32,'全唐诗/poet.song.178000.json','["十日之間我欲回，仍於真隠一尊開。", "東游西泛多情致，應喜其間得句來。"]'),
