('a0d2898b-6a3e-428f-a43f-cda596b3dded','徐子顔挽章  其三','韓淲','宋','宋诗','song-poetry','','[]','堅坐山頭十數年，後來卜築轉蕭然。',32,'全唐诗/poet.song.178000.json','["堅坐山頭十數年，後來卜築轉蕭然。", "古梅風折籬傾倒，朱橘空垂屋角邊。"]'),
('5a99c796-a449-43aa-bad6-66d4d95a8fa1','徐子顔挽章  其四','韓淲','宋','宋诗','song-poetry','','[]','門外曾聽刺史車，也令鄉國重貧儒。',32,'全唐诗/poet.song.178000.json','["門外曾聽刺史車，也令鄉國重貧儒。", "傷心又賻君之葬，此事應須近日無。"]'),
('ada6e672-944c-460f-ba16-8888fa931a3c','徐子顔挽章  其五','韓淲','宋','宋诗','song-poetry','','[]','人營家室因妻子，二者何能一一賢。',32,'全唐诗/poet.song.178000.json','["人營家室因妻子，二者何能一一賢。", "到底伶俜反無累，反乎真宅總如然。"]'),
('55c51672-bd7a-4b99-a1b0-ae3a633543f3','徐子顔挽章  其六','韓淲','宋','宋诗','song-poetry','','[]','霜風漠漠葉闌斑，積水陂池映淺山。',32,'全唐诗/poet.song.178000.json','["霜風漠漠葉闌斑，積水陂池映淺山。", "氣盡斂形陰野土，一生心事白雲閒。"]'),
('1672e210-5e65-4700-ad8f-de89108eb259','徐子顔挽章  其七','韓淲','宋','宋诗','song-poetry','','[]','覆雨翻雲以利名，漢庭無日不公卿。',32,'全唐诗/poet.song.178000.json','["覆雨翻雲以利名，漢庭無日不公卿。", "試言行志今誰是，却羨長貧過此生。"]'),
('459b3880-3ef3-452b-8015-e405010ede95','徐子顔挽章  其八','韓淲','宋','宋诗','song-poetry','','[]','宗人相送入山阿，誰挽誰扶誰作歌。',32,'全唐诗/poet.song.178000.json','["宗人相送入山阿，誰挽誰扶誰作歌。", "既老無家且無子，不知君者謂如何。"]'),
('3ebfc128-e1f5-4852-b08b-315cc486d22a','徐子顔挽章  其九','韓淲','宋','宋诗','song-poetry','','[]','常與交朋奉杖藜，放懷携手動移時。',32,'全唐诗/poet.song.178000.json','["常與交朋奉杖藜，放懷携手動移時。", "蒼茫溪北溪南路，忍對交朋只自知。"]'),
('942983d4-bab0-4658-a241-74e08edd8f24','徐子顔挽章  其一○','韓淲','宋','宋诗','song-poetry','','[]','談天談佛共談仙，靜裏光陰不計年。',32,'全唐诗/poet.song.178000.json','["談天談佛共談仙，靜裏光陰不計年。", "幾度過家扶醉去，豈知今日見沉泉。"]'),
('b49c2b66-4dc2-4ee5-b679-7bc88b5721cd','懷古','韓淲','宋','宋诗','song-poetry','','[]','往來是日月，變動是寒暑。',48,'全唐诗/poet.song.178000.json','["往來是日月，變動是寒暑。", "伏臘雖不周，爾且對妻子。", "遥知風塵表，萬象互吞吐。", "所以鹿門人，江左不得取。"]'),
('82dae1cd-1431-4c74-8e9b-9bd1ccb0c347','五月十日','韓淲','宋','宋诗','song-poetry','','[]','片月生林白，沿流澗亦明。',48,'全唐诗/poet.song.178000.json','["片月生林白，沿流澗亦明。", "幽人方獨夜，山寺有微行。", "野處偏宜夏，貧家不厭晴。", "薰風吹老鬢，腐草見飛螢。"]'),
('a9f47bc9-23f4-4c4f-a41f-29e825a68024','七月三首  其一','韓淲','宋','宋诗','song-poetry','','[]','地僻稀人迹，重林日自虛。',48,'全唐诗/poet.song.178000.json','["地僻稀人迹，重林日自虛。", "鳥飛晨氣外，蟬噪晚涼初。", "餘潤從侵屨，浮埃倦整書。", "樵漁時上下，閉戶又何居。"]'),
('5ee30841-e111-4e1b-af99-fc45c1aee0b4','七月三首  其二','韓淲','宋','宋诗','song-poetry','','[]','木末芙蓉起，亭亭綠且青。',48,'全唐诗/poet.song.178000.json','["木末芙蓉起，亭亭綠且青。", "牆猶承片瓦，窗不礙疎櫺。", "次第花擎蓋，縱橫葉展屏。", "石丁誰主者，仙豈待沉冥。"]'),
('c333b49f-046d-47e5-8930-ebeae14e7b53','七月三首  其三','韓淲','宋','宋诗','song-poetry','','[]','擁砌叢生菊，何關老意多。',48,'全唐诗/poet.song.178000.json','["擁砌叢生菊，何關老意多。", "澆花驚易燥，耘草喜成科。", "枕腊尤宜睡，餐香豈待哦。", "淵明藏不盡，滿把尚婆婆。"]'),
('2c57e396-d837-414e-9bcb-7fa152935100','中秋呈潘德久','韓淲','宋','宋诗','song-poetry','','[]','一年明月在中秋，數日陰雲不奈愁。',64,'全唐诗/poet.song.178000.json','["一年明月在中秋，數日陰雲不奈愁。", "忽喜新晴轉書室，極知清夜照歌樓。", "醉當弄影如坡老，詩就撞鐘憶貫休。", "千里故人應若此，吾生常好更何求。"]'),
('fd4ccd30-e37f-4045-84e9-a5a8dd7eac98','鵝湖道中  其一','韓淲','宋','宋诗','song-poetry','','[]','野花狼藉雨初晴，人在山南山北行。',32,'全唐诗/poet.song.178000.json','["野花狼藉雨初晴，人在山南山北行。", "東風淺淺尚寒色，雲映遠天斜照明。"]'),
('f9d026f4-50d1-414a-a488-8ea6f7639834','鵝湖道中  其二','韓淲','宋','宋诗','song-poetry','','[]','高田下田流水聲，前村後村鵓鳩鳴。',32,'全唐诗/poet.song.178000.json','["高田下田流水聲，前村後村鵓鳩鳴。", "山礬已開桃已謝，霏霏小雨未成晴。"]'),
('34f3f765-a901-48ad-b1fc-dc7f05b01fed','鵝湖道中  其三','韓淲','宋','宋诗','song-poetry','','[]','雨斜風驟樹連雲，荒遠人家酒不村。',32,'全唐诗/poet.song.178000.json','["雨斜風驟樹連雲，荒遠人家酒不村。", "小醉未成愁又入，更無情緒到清樽。"]'),
('b404894b-bff4-49ca-8279-9340abe05707','鵝湖道中  其四','韓淲','宋','宋诗','song-poetry','','[]','青松影裏小桃花，山崦橫岡人幾家。',32,'全唐诗/poet.song.178000.json','["青松影裏小桃花，山崦橫岡人幾家。", "牧童樵子自來往，水擁斷溝留殘沙。"]'),
('30def53a-d19b-4166-a984-062913062b05','周國正約過茶山带湖','韓淲','宋','宋诗','song-poetry','','[]','青春行樂耳，誰無一林園。',60,'全唐诗/poet.song.178000.json','["青春行樂耳，誰無一林園。", "餘陰斂宿雨，桃李亦復暄。", "坐閒語句到，酒半情意宣。", "從容出處易，緬邈聚散難。", "記此野城北，望望橫靈山。"]'),
('307da48d-eef2-4e81-9eda-db82365ca881','次公招看綠萼梅和韵','韓淲','宋','宋诗','song-poetry','','[]','春山有梅，萼綠香潔。',40,'全唐诗/poet.song.178000.json','["春山有梅，萼綠香潔。", "愛雪宜霜，憑風藉月。", "花已開明，枝復橫絕。", "翠袖天寒，供吟試折。"]'),
('23f06c35-ccc0-4630-9265-63c1322a7f1d','二十五日舒村','韓淲','宋','宋诗','song-poetry','','[]','秋水澄溪淥，秋山遠岸青。',24,'全唐诗/poet.song.178000.json','["秋水澄溪淥，秋山遠岸青。", "村酤因覓句，雅放却嫌醒。"]'),
('a4bd2487-fb6d-48ff-bd7f-e61c83cf2a4a','深村','韓淲','宋','宋诗','song-poetry','','[]','已是依山住，更爲深村行。',48,'全唐诗/poet.song.178000.json','["已是依山住，更爲深村行。", "莽莽少人迹，幽幽聞鳥聲。", "忽逢三四家，草樹亦敷榮。", "不覺六七里，煙靄還縱橫。"]'),
('ca22bb5f-376d-4a1e-b21f-01136eeb9325','初八日傳聞光州虜退又云東海之捷','韓淲','宋','宋诗','song-poetry','','[]','疆埸未云靜，家國疑摇摇。',180,'全唐诗/poet.song.178000.json','["疆埸未云靜，家國疑摇摇。", "深乎帷帳籌，公卿日以朝。", "虜勢固不壯，虜騎固爲驍。", "强弱士氣少，戰守民力凋。", "荒山澗壑冷，歲暮風蕭蕭。", "百草皆爛死，撲面黄葉飄。", "梟鶹互鳴嘯，狐豺紛躑跳。", "禿鬢祗枯藜，竚立天益寥。", "恭惟我壽皇，恢復悉有條。", "咄哉開禧臣，妄動尤虛囂。", "女貞亦分裂，幽燕亂無聊。", "賢愚世運厄，隆替華夏焦。", "羌戎漢威靈，河隍唐僖昭。", "民老曾何知，但願歸富饒。", "中外持論平，致君舜與堯。"]'),
('01401916-5ba8-4045-9f35-f4f26d8da1a1','故友不可見新相知者有數','韓淲','宋','宋诗','song-poetry','','[]','老覺賓朋日日稀，故家言語轉依違。',64,'全唐诗/poet.song.178000.json','["老覺賓朋日日稀，故家言語轉依違。", "百年以往自興廢，千古其間誰是非。", "江左風流徒可想，山東豪傑竟何歸。", "勾吳於越連閩嶠，瘴雨蠻烟百鳥飛。"]'),
('207fcaf2-49e0-4bbf-9751-f6e882273719','題孫伯符墓','韓淲','宋','宋诗','song-poetry','','[]','自無太史慈，孰對孫伯符。',168,'全唐诗/poet.song.178000.json','["自無太史慈，孰對孫伯符。", "羣舒有餘地，周郎或知予。", "既推道南宅，以濕謾相濡。", "本擬馳中原，掃滅鄴中都。", "天乎許貢客，一箭失壯軀。", "黽勉付後事，張昭乃其奴。", "赤壁之火攻，僅可保全吳。", "公瑾復不長，伯業益荒蕪。", "至今春草生，高墳在姑蘇。", "傳言尚相點，經行倍踟躕。", "異代歲月速，誰爲我非夫。", "酹酒起英爽，白楊鳴赤烏。", "荆州或已分，曹劉竟稱孤。", "堂堂破虜冢，歸命誠足俘。"]'),
('c478dcce-9ed0-4c80-9720-4bed5f2cb085','句','韓淲','宋','宋诗','song-poetry','','[]','玄機未易窺。',6,'全唐诗/poet.song.178000.json','["玄機未易窺。"]'),
('d8e54833-9f81-4ffd-9ee9-e4616e2c18fe','存目','韓淲','宋','宋诗','song-poetry','','[]','詩題：王禹偁贈呂通秘楚州監倉首句：聞君公事苦喧卑。',25,'全唐诗/poet.song.178000.json','["詩題：王禹偁贈呂通秘楚州監倉首句：聞君公事苦喧卑。"]'),
('b7c9218a-b74e-4704-b297-6c28a8d3e66f','水心先生墓下作','王汶','宋','宋诗','song-poetry','','[]','排雲上殊庭，備物儼神道。',168,'全唐诗/poet.song.178000.json','["排雲上殊庭，備物儼神道。", "含酸步逶迤，積疹思遐漂。", "乘風來帝旁，駕說落窮島。", "百聖集會期，萬化資斧藻。", "瞻前鳳漂漂，顧後龍矯矯。", "寶璐列中華，韶音被夷獠。", "肅肅闕里牆，萋萋墓林草。", "誰尸兩楹夢，而復悲一老。", "曩余稚養蒙，今日幸茹蓼。", "超然欲徑陳，窅爾竟虛抱。", "育德德何成，果行行何造。", "沔彼江海流，不納此行潦。", "青松露珠團，怪石紫煙遶。", "千年萬年垂，封樹等穹昊。"]'),
('46d5b09c-3120-43f2-8d68-8630a4df9012','寄韓澗泉三首  其一','王汶','宋','宋诗','song-poetry','','[]','達人貴適己，脫屣離王庭。',72,'全唐诗/poet.song.178000.json','["達人貴適己，脫屣離王庭。", "袖此轉物手，悅我違俗醒。", "睆彼岐山鳥，揚光來青冥。", "豈其覽德輝，而肯啄腐腥。", "翻雲吐嘉音，濯露潔脩翎。", "紛紛世網密，何由覿爾形。"]'),
('50e53a66-16c3-42a7-8b20-696af57d67f8','寄韓澗泉三首  其二','王汶','宋','宋诗','song-poetry','','[]','在困多促促，長懷特栖者。',72,'全唐诗/poet.song.178000.json','["在困多促促，長懷特栖者。", "崔嵬玉山岑，今誰秣余馬。", "朝隨澗雲浮，暮逐澗泉瀉。", "光儀儼神交，晤言寄心寫。", "食魚不知肥，采菊不盈把。", "願垂白日影，照我蔀屋下。"]'),
('0ee6ec9a-e49e-4018-9d78-6d8ccf02a87d','寄韓澗泉三首  其三','王汶','宋','宋诗','song-poetry','','[]','浮榮安可搴，高蹈何恨早。',72,'全唐诗/poet.song.178000.json','["浮榮安可搴，高蹈何恨早。", "處則爲遠志，出則爲小草。", "脩名隨風翔，嘉遯若龍矯。", "棲遲二十年，匣此不世寶。", "灝露團紅蘭，涼吹發清昊。", "因知吐芳訊，慰我夙昔抱。"]'),
('8385d4b7-67c7-48e4-bfe4-a2be270c8946','送應顯夫之上饒','王汶','宋','宋诗','song-poetry','','[]','細雨杏花斑，飛飛燕子還。',48,'全唐诗/poet.song.178000.json','["細雨杏花斑，飛飛燕子還。", "人隨煙棹去，門對釣磯閒。", "曉月偏驚夢，春雲不離山。", "定知多好句，音問盍相關。"]'),
('6016685c-4186-496d-a7c3-b7ee2fba2879','寄葛元成','王汶','宋','宋诗','song-poetry','','[]','子規啼不歇，君向越山聽。',48,'全唐诗/poet.song.178000.json','["子規啼不歇，君向越山聽。", "既已疎吟伴，誰當共酒瓶。", "松花全是粉，柳絮半爲萍。", "自笑無生計，閒箋相鶴經。"]'),
('596b7e83-e2cb-4e07-b77a-9a676f204849','有懷蔡貫之子與','王汶','宋','宋诗','song-poetry','','[]','相看計盡非，息影更何疑。',48,'全唐诗/poet.song.178000.json','["相看計盡非，息影更何疑。", "幾日雁初過，一冬寒較遲。", "竹宜和雪看，梅好带花移。", "只此清貧趣，知心者是誰。"]'),
('885952f2-0f71-40a9-be65-279965a17579','題韓仲止壁二首  其一','余儔','宋','宋诗','song-poetry','','[]','謁入久不出，兀坐如枯荄。',48,'全唐诗/poet.song.178000.json','["謁入久不出，兀坐如枯荄。", "蒼頭前致詞，問我何因來。", "士節久凋喪，人情易嫌猜。", "本無性命憂，不去安待哉。"]'),
('b24b2afe-dbf4-4e2a-b93e-89df075a515a','題韓仲止壁二首  其二','余儔','宋','宋诗','song-poetry','','[]','名聞由昔者，禮進合欣然。',48,'全唐诗/poet.song.178000.json','["名聞由昔者，禮進合欣然。", "古有不屑教，意令加後鞭。", "尚書八座貴，吏部一燈傳。", "驚代文章伯，曾容賈浪仙。"]'),
('9660154f-4c1a-47cc-ac93-64fa76c3e01d','遊水樂洞','王大受','宋','宋诗','song-poetry','','[]','歷聘空寒六六天，更來洗耳聽春泉。',64,'全唐诗/poet.song.178000.json','["歷聘空寒六六天，更來洗耳聽春泉。", "迅湍激石浮清磬，懸溜行沙寫素弦。", "洞口林亭三四曲，洞中日月幾千年。", "何人獨得開收律，譜入宮商與世傳。"]'),
('8d1b1039-6850-4363-9d6d-488f84cb23e2','遊鹿苑寺','王大受','宋','宋诗','song-poetry','','[]','鷲峰遊屐少，我獨住多時。',48,'全唐诗/poet.song.178000.json','["鷲峰遊屐少，我獨住多時。", "僧護翻經石，猿攀礙月枝。", "地寒春到晚，山遠夢歸遲。", "尚被浮名誤，吾心信自癡。"]'),
('040d1eb7-f323-4435-8e76-68a4c7ac6e94','客枕','王大受','宋','宋诗','song-poetry','','[]','山居猿狖最多情，嘯月吟風伴醉醒。',32,'全唐诗/poet.song.178000.json','["山居猿狖最多情，嘯月吟風伴醉醒。", "昨夜數聲霜雪外，元來不比在家聽。"]'),
('4d430256-9aec-49ad-8ec8-4b8a6f54b433','玉山道中','王大受','宋','宋诗','song-poetry','','[]','夜夜還家夢，行行撲面風。',48,'全唐诗/poet.song.178000.json','["夜夜還家夢，行行撲面風。", "征塵添老色，酒病重詩窮。", "世路方行險，吾生且轉蓬。", "天涯重回首，愁滿夕陽中。"]'),
('f18c1293-9b2e-4356-9b03-c67d776b3a7f','曝書','王大受','宋','宋诗','song-poetry','','[]','歲月如流書似山，豈堪檢點鬢毛斑。',64,'全唐诗/poet.song.178000.json','["歲月如流書似山，豈堪檢點鬢毛斑。", "貧憂消耗記持少，場屋羈縻展拓難。", "事物無窮徒著眼，身心未了只長歎。", "直須種種從頭掃，掃到和書也不看。"]'),
('99af5aa5-be2b-478c-bdf1-df7db3549cf0','句  其一','王大受','宋','宋诗','song-poetry','','[]','君不見牛奇章與李衛公，二人平生不相容。',35,'全唐诗/poet.song.178000.json','["君不見牛奇章與李衛公，二人平生不相容。", "門前冠蓋互咿軋，惟有愛石心則同。"]'),
('60bf61ab-0478-4c0a-bdb3-895b6fa0d55c','句  其二','王大受','宋','宋诗','song-poetry','','[]','波軟夕陽紅。',6,'全唐诗/poet.song.178000.json','["波軟夕陽紅。"]'),
('972d15e7-66e7-4404-9f38-1aba50da02fa','句  其三','王大受','宋','宋诗','song-poetry','','[]','岸拖秋草綠。',6,'全唐诗/poet.song.178000.json','["岸拖秋草綠。"]'),
('c44f2807-30ad-4327-af7c-0488480fd890','句  其四','王大受','宋','宋诗','song-poetry','','[]','有分長爲客。',6,'全唐诗/poet.song.178000.json','["有分長爲客。"]'),
('fa9f8e55-79e1-492d-8c2d-da2e788f5c08','句  其五','王大受','宋','宋诗','song-poetry','','[]','江平不見灘。',6,'全唐诗/poet.song.178000.json','["江平不見灘。"]'),
