('9f32e90d-0441-470e-9cc8-8b8266bef29d','句  其七','王大受','宋','宋诗','song-poetry','','[]','山行千巖翠作堆。',8,'全唐诗/poet.song.178000.json','["山行千巖翠作堆。"]'),
('57641d40-1df1-4316-ad44-71447acad1d8','句  其八','王大受','宋','宋诗','song-poetry','','[]','白雲深處小橋橫。',8,'全唐诗/poet.song.178000.json','["白雲深處小橋橫。"]'),
('8353b302-5c01-4887-9c37-fae21391beda','挽蔡西山先生','劉礪','宋','宋诗','song-poetry','','[]','念昔摳衣日，寧知輩行殊。',48,'全唐诗/poet.song.178000.json','["念昔摳衣日，寧知輩行殊。", "師才驚宇宙，鄙學困蟲魚。", "紀曆深皇極，談兵淺律書。", "傷心濂水別，有惑更誰袪。"]'),
('46350a9e-e5d2-468c-bcb3-6ac73a5eac13','浯溪','臧辛伯','宋','宋诗','song-poetry','','[]','四山凝碧一江橫，讀盡唐碑萬感生。',32,'全唐诗/poet.song.178000.json','["四山凝碧一江橫，讀盡唐碑萬感生。", "却想老僊明月夜，度香橋下聽溪聲。"]'),
('85e8536e-0f05-4c1d-a798-73c9bf72571e','澹巖','臧辛伯','宋','宋诗','song-poetry','','[]','元柳搜奇□□□，□□□□□詩傳。',64,'全唐诗/poet.song.178000.json','["元柳搜奇□□□，□□□□□詩傳。", "眼看巖□□□□，□□□明却有天。", "溜□□□□□□，□藤穿壁鏁晴□。", "□□□□□□古，望斷飛鴻夕照邊。"]'),
('e6632a7e-e656-4ad5-bf88-d07434777c66','御風亭','鄧仲倚','宋','宋诗','song-poetry','','[]','飲醉歸時戶欲扃，煙喧棲鳥噪荒荆。',64,'全唐诗/poet.song.178000.json','["飲醉歸時戶欲扃，煙喧棲鳥噪荒荆。", "飄颻萬里鵬程遠，縹緲三山鶴駕輕。", "秋樹涼生空過鷁，暮雲光動海翻鯨。", "酒徒他日如相問，爲拂塵埃看姓名。"]'),
('cc226ddf-1b5c-44b4-840b-048eb1ba65a5','抵袁陽  其一','施德','宋','宋诗','song-poetry','','[]','聲聲啼鳴叫鉤輈，山自巑岏水自流。',32,'全唐诗/poet.song.178000.json','["聲聲啼鳴叫鉤輈，山自巑岏水自流。", "西望長沙三百里，行人道是古袁州。"]'),
('f65e6365-b8ce-412d-a07f-7eeedceb0e1c','抵袁陽  其二','施德','宋','宋诗','song-poetry','','[]','曲磵縈紆樹密蒙，放船正值楝花風。',32,'全唐诗/poet.song.178000.json','["曲磵縈紆樹密蒙，放船正值楝花風。", "王程不及村南好，水碓無人晝自舂。"]'),
('ee04c799-fdbf-4b0d-be04-1b5aa34b0935','句  其一','陳詩','宋','宋诗','song-poetry','','[]','如何五載後，不問九疑歸。',12,'全唐诗/poet.song.178000.json','["如何五載後，不問九疑歸。"]'),
('9dc9e573-7d24-4452-9192-2b02a85cb7e2','句  其二','陳詩','宋','宋诗','song-poetry','','[]','瑩光連燭動，月影带河流。',12,'全唐诗/poet.song.178000.json','["瑩光連燭動，月影带河流。"]'),
('f8c41bb3-b90f-4f95-ab0b-0c49768062ea','和傅子雲見贈','桂聞詩','宋','宋诗','song-poetry','','[]','客袖衝寒至，飄飄不受羈。',48,'全唐诗/poet.song.178000.json','["客袖衝寒至，飄飄不受羈。", "笑呵雙兔筦，亟寫錦囊詩。", "雖我斑毛薄，多君青眼垂。", "別懷無處著，隨夢到春池。"]'),
('49f25331-9476-40ce-927a-50a15698b655','松風亭','趙良生','宋','宋诗','song-poetry','','[]','七樹懷鄭薰，千尺羨晉嶠。',24,'全唐诗/poet.song.178000.json','["七樹懷鄭薰，千尺羨晉嶠。", "弘景招不來，俯仰但長嘯。"]'),
('03b0321d-29d0-4be6-8471-548d43e35e5c','贈大慈寺嘯翁開士','史守之','宋','宋诗','song-poetry','','[]','挂錫雲飛處，心閑境亦閑。',48,'全唐诗/poet.song.178000.json','["挂錫雲飛處，心閑境亦閑。", "萬緣空俗想，一鉢飽松關。", "身幻從茲化，風高未許攀。", "繁華滿眼底，付與水潺潺。"]'),
('d223a2b8-e2c0-488a-a3a9-eb806c44cf83','題資福院平綠軒','輔廣','宋','宋诗','song-poetry','','[]','名區與利壠，羊腸競攀躋。',120,'全唐诗/poet.song.178000.json','["名區與利壠，羊腸競攀躋。", "誰能爲芳草，四曠成幽棲。", "春風一憑欄，秀色無高低。", "山遥不作障，水近何妨隄。", "只恐金氣寒，黄枯變碧萋。", "坐令羣目驚，有似七聖迷。", "人心無天遊，六鑿相攘擠。", "但於平處觀，衆有何端倪。", "日月互賓送，景物隨乖暌。", "彼昏如執著，惟君試金篦。"]'),
('be080d14-ebb7-4d06-8942-4bd7221cd659','春日詞','常某','宋','宋诗','song-poetry','','[]','庭院深深春日遲，百花落盡蜂蝶稀。',96,'全唐诗/poet.song.178000.json','["庭院深深春日遲，百花落盡蜂蝶稀。", "柳絮隨風不拘管，飛入洞房人不知。", "畫堂繡幕垂朱戶，玉爐消盡沉香炷。", "半褰斗帳曲屏山，盡日梁間雙燕語。", "美人睡起歛翠眉，强臨鸞鑒不勝衣。", "門外鞦韆一笑發，馬上行人斷腸歸。"]'),
('f99d0222-04b6-4f81-82e3-4f7d1f3de4aa','和範孫閑行溪西得梅數花韻  其一','杜知仁','宋','宋诗','song-poetry','','[]','寒梅我故人，歲必以文會。',168,'全唐诗/poet.song.178000.json','["寒梅我故人，歲必以文會。", "涴墨尚可覆，未知凡幾醉。", "晚乃得此詩，山靈以爲最。", "置身風月上，出語色香外。", "駕言孤絕處，壞枝委顛沛。", "懸崖折披竹，斷澗强病檜。", "窮交僅如此，過是藐無輩。", "碧眼苦好奇，於焉有深嗜。", "迎長得一花，以爲時可矣。", "遂若天下春，筆頭頓生氣。", "我屬閉關日，一枝偕寤寐。", "敢賀微陽來，尚虞堅冰至。", "結束果何在，飄零初不計。", "政恐負歲寒，或爲識者喟。"]'),
('d19dc693-4a76-4508-a62b-7a8947e1f50e','和範孫閑行溪西得梅數花韻  其二','杜知仁','宋','宋诗','song-poetry','','[]','孤根要先覺，一花已後會。',168,'全唐诗/poet.song.178000.json','["孤根要先覺，一花已後會。", "而况萬香中，晚乃誇狂醉。", "東皇兆群物，無物居其最。", "對梅欲著語，當在梅之外。", "君看龍蛇蟄，中有江河沛。", "其元陽復雷，其真歲寒檜。", "於梅觀此妙，眼力憐湛輩。", "無能根本求，僅爲色香嗜。", "一元無識者，孤真可知矣。", "君獨邃玄機，命筆開風氣。", "奇哉天根詞，與世呼夢寐。", "猶疑轉語下，未爲梅之至。", "願聞第一義，更作向上計。", "會有先天翁，當發無極喟。"]'),
('ab311ca8-c7f5-4191-9184-f4b8d7136874','清溪','陳章','宋','宋诗','song-poetry','','[]','滄波萬頃無纖塵，沙鷗兩兩來相親。',32,'全唐诗/poet.song.178000.json','["滄波萬頃無纖塵，沙鷗兩兩來相親。", "主人忘機鷗不去，此時此景皆天真。"]'),
('afd41da6-8a94-4f87-bcb7-ab38d07c904a','遊九鎖','鍾穎','宋','宋诗','song-poetry','','[]','大滌通華陽，仙家碧雲上。',48,'全唐诗/poet.song.178000.json','["大滌通華陽，仙家碧雲上。", "飛泉舞蒼蛟，絕壁浮翠浪。", "泉石有聲詩，雲煙無盡藏。", "落日青山多，臨風一長望。"]'),
('b1e58563-dd25-41c8-a0f6-84f862ea5766','賢令山','張本中','宋','宋诗','song-poetry','','[]','□□縈紆一徑深，□看石壁起千音。',64,'全唐诗/poet.song.178000.json','["□□縈紆一徑深，□看石壁起千音。", "雨□□□來春溜，霧靄留空□晝陰。", "坐對雲山開遠眼，靜諧泉石會幽吟。", "山陰東武定何□，妙趣何曾間古今。"]'),
('b15871f9-a698-49ad-b567-9fcef2c10796','詠丹桂','胡榘','宋','宋诗','song-poetry','','[]','碎瓊揉香作肌骨，霽日吹紅染膚色。',255,'全唐诗/poet.song.178000.json','["碎瓊揉香作肌骨，霽日吹紅染膚色。", "人間何處有此葩，一種風流初未識。", "東隅月戶編三千，夜修玉闕瀛洲前。", "拂摇桂子偶墜此，雨露培植開韶妍。", "史翁移根出葱蒨，雕斛持歸翠微殿。", "一朝麗質冠百昌，御墨分題落團扇。", "何年流轉江南鄉，一本奚翅千金償。", "分枝接葉色已淺，縱有此花無此香。", "絕愛西山佳麗地，藹藹修林倚清吹。", "寧論斜日杏花酣，未許熙春海棠睡。", "是時金氣初高明，宇宙軒豁澄埃氛。", "青霞絳雪互點綴，濃芬賸馥飄氤氳。", "鷲峰繁黄今不數，破裓僧練裙女。", "試看香御擁紅雲，肅奉虛皇遊碧宇。", "携持寶鏡吹波金，寒光萬頃空人心。", "煩君控取紅鸞住，便恐香魂夜飛去。"]'),
('27fdb136-6c9c-4fed-b195-6ba2e3321565','次忠定史越王丹桂韻','胡榘','宋','宋诗','song-poetry','','[]','霧隠森森小山碧，不嫁東風矜國色。',260,'全唐诗/poet.song.178000.json','["霧隠森森小山碧，不嫁東風矜國色。", "流芳端自蕊珠仙，曾是先皇親拔識。", "一身便足當三千，氣韻乃在黄香前。", "聊同蕖菊領秋色，不與桃李爭春妍。", "日幄雲幛護青蒨，丹霞爲臺月爲殿。", "露滋韶豔染猩袍，風引清芬吹雉扇。", "結根只合帝子鄉，價重未可瓊瑶償。", "濟川小試舟楫利，作醴更助椒蘭香。", "仙籍英聲在丹地，紫殿名高非濫吹。", "影斜遥漢玉蟾寒，香渡鎖窗金鴨睡。", "運際千齡遭聖明，氣使萬里開塵氛。", "一枝昔已擅風采，五方今正傳氤氳。", "後塵江梅誰比數，獨抱孤根對青女。", "幸分餘馥霑後來，一吐寒花照霜宇。", "佇看一諾輕千金，嫣然顧笑舒丹心。", "願公千秋長在廣寒宮裏住，容我驂鸞共來去。"]'),
('ceb0086d-7cd4-4329-b89c-001d157d6ff8','濠梁凱歌','胡榘','宋','宋诗','song-poetry','','[]','春殘天氣何佳哉，捷書夜自濠梁來。',256,'全唐诗/poet.song.178000.json','["春殘天氣何佳哉，捷書夜自濠梁來。", "將軍生擒僞駙馬，虜兵十萬冰山摧。", "何物輕獧胡羯，萬里烟塵暗邊徼。", "邊臣玩寇不却攘，三月淮堧蹀血。", "廟謨密遣山東兵，李將軍者推忠精。", "鐵鎗匹馬首破陣，喑嗚叱咤風雲生。", "摧殺群妖天與力，虜醜成擒不容逸。", "失聲走透虜鼓搥，猶截騰驤三百匹。", "防圍健使催賜金，曹家莊畔殺胡林。", "遊魂欲反定懸膽，將軍豈知關塞深。", "君不見往日蘄王邀兀朮，圍合狐跳追不得。", "夫人明日拜函封，乞罪將軍縱狂逸。", "豈知李侯心膽粗，捕縛猘纔須臾。", "金牛走敵猛將有，沔州斬賊儒生無。", "宗社威靈人制勝，養銳圖全無輕進。", "會須入汴縛酆王，笳鼓歸來取金印。"]'),
('5f95cfbf-784b-44d6-94b3-783fd312a5e9','嘉定二年秋重遊洞霄宮','胡榘','宋','宋诗','song-poetry','','[]','重尋九鎖躡丹梯，回首空驚歲月移。',64,'全唐诗/poet.song.178000.json','["重尋九鎖躡丹梯，回首空驚歲月移。", "風虎守閽寧易到，冰龍候路却先馳。", "松筠老去俱全節，猿鶴迎來盡故知。", "更拂棲真洞間石，弟兄同記勝游時。"]'),
('b7b23847-a212-4d1a-ad12-9e6deba950d4','遊玉巖即事','胡榘','宋','宋诗','song-poetry','','[]','誰穿石竇徹瑶空，絕勝吾儒一畝宮。',32,'全唐诗/poet.song.178000.json','["誰穿石竇徹瑶空，絕勝吾儒一畝宮。", "縱使風雲來蔽塞，此心原自與天通。"]'),
('cf2f9bdf-1c8c-4b7e-889d-2dbc081ede6e','玉巖石刻','胡榘','宋','宋诗','song-poetry','','[]','清獻濂溪二老仙，風流俯仰一時賢。',32,'全唐诗/poet.song.178000.json','["清獻濂溪二老仙，風流俯仰一時賢。", "摩挲石刻追前躅，坡叟遺文媿續鎸。"]'),
('023da457-da0a-4dee-aec4-50863c8551bc','玉巖忘歸','胡榘','宋','宋诗','song-poetry','','[]','穹巖如屋聳翬飛，竹樹參差一徑微。',32,'全唐诗/poet.song.178000.json','["穹巖如屋聳翬飛，竹樹參差一徑微。", "凌絕空虛真出世，徘徊朝夕竟忘歸。"]'),
('20d79510-cc73-41f1-a7df-be60be66b4bb','玉巖遺蹟','胡榘','宋','宋诗','song-poetry','','[]','陽公舊隠尚依然，鬰鬰松筠鎖翠烟。',32,'全唐诗/poet.song.178000.json','["陽公舊隠尚依然，鬰鬰松筠鎖翠烟。", "一世辛勤躬筆墨，只緣種玉不逢年。"]'),
('4a625bb9-f85b-4fd8-af3f-589893618146','挽莫與倫','胡榘','宋','宋诗','song-poetry','','[]','三顧無人憶草廬，藻江文海竟何如。',64,'全唐诗/poet.song.178000.json','["三顧無人憶草廬，藻江文海竟何如。", "馬卿早已羞逢掖，狗監誰能薦子虛。", "曠達嗣宗貧嗜酒，清高元晏老耽書。", "南州人物今如許，深惜霜林一夜疎。"]'),
('10252097-5117-48a2-b985-7326bb16a05b','題清音亭','胡榘','宋','宋诗','song-poetry','','[]','天柱峰頭吐細泉，清音亭下玉琅然。',32,'全唐诗/poet.song.178000.json','["天柱峰頭吐細泉，清音亭下玉琅然。", "可能爲滌肝腸滓，容我超摇五洞天。"]'),
('daabd191-8f07-4360-b8d9-33e8ca64bcfb','題翠蛟亭','胡榘','宋','宋诗','song-poetry','','[]','山英藏水巧能欺，動地雷聲發駭機。',64,'全唐诗/poet.song.178000.json','["山英藏水巧能欺，動地雷聲發駭機。", "驚看玉淵千浪聳，挽回銀浦一支飛。", "流霞未引松花酒，湔雪先霑槲葉衣。", "坐覺群仙生起色，倒傾蛟室瀉珠璣。"]'),
('7a154859-0178-45c9-89b4-5e4da2d6ece8','游洞霄宮','胡榘','宋','宋诗','song-poetry','','[]','青山九鎖洞霄宮，真氣澄鮮瑞霧濃。',64,'全唐诗/poet.song.178000.json','["青山九鎖洞霄宮，真氣澄鮮瑞霧濃。", "扈聖千齡開蕊館，擎天一柱削瓊峰。", "丹崖不見凌雲鳳，翠峽驚看躍雪龍。", "湔拂京華塵土累，冥鴻何處更求蹤。"]'),
('75db7dfb-5a87-48d2-ac6f-86b425a38c37','重游洞霄宮','胡榘','宋','宋诗','song-poetry','','[]','蛟鰐讒波偶脫身，洞霄真境浣妖氛。',64,'全唐诗/poet.song.178000.json','["蛟鰐讒波偶脫身，洞霄真境浣妖氛。", "未妨貰酒餘杭姥，重與題詩大滌雲。", "何自玉關休戰鼓，儻容瓊館秦爐熏。", "第憂負愧麑裘老，馴虎巖前有勒文。"]'),
('70f77637-f0c1-4539-907c-a74c2dcf4d02','洞霄紀游','胡榘','宋','宋诗','song-poetry','','[]','洞霄真境踰前聞，青山九鎖仙塵分。',128,'全唐诗/poet.song.178000.json','["洞霄真境踰前聞，青山九鎖仙塵分。", "先皇登臨既冠絕，宰輔典領仍繽紛。", "邇來煙霞全屬□，五洞交扃無不鎖。", "羽人談笑許卜隣，群從追隨清作火。", "古松化石餘古杉，坡翁妙語留東巖。", "幾年反骨更刮垢，一旦蛻跡應超凡。", "閲世推移本無住，華表區區欲誰語。", "它年此地紀昔游，一劍橫空自來去。"]'),
('ab25c9e8-17ab-43e9-a663-a7248d494417','翠蛟峰','胡榘','宋','宋诗','song-poetry','','[]','像聳奇形曰翠蛟，不須牙爪謾徒勞。',32,'全唐诗/poet.song.178000.json','["像聳奇形曰翠蛟，不須牙爪謾徒勞。", "須臾變化非難事，况有飛泉作怒濤。"]'),
('6588ec8a-5542-4457-84ae-f076a9d3ac56','句','胡榘','宋','宋诗','song-poetry','','[]','自孤花底三更月，却怨樓頭一笛風。',16,'全唐诗/poet.song.178000.json','["自孤花底三更月，却怨樓頭一笛風。"]'),
('347ed10f-9244-46b9-96bc-3d55c5605bec','存目','胡榘','宋','宋诗','song-poetry','','[]','詩題：嘉定二年秋重遊洞霄首句：餘杭泉石欠幽探。',23,'全唐诗/poet.song.178000.json','["詩題：嘉定二年秋重遊洞霄首句：餘杭泉石欠幽探。"]'),
('7506dca3-2c1b-43bc-b38e-b3139e294c15','句','趙不謭','宋','宋诗','song-poetry','','[]','信史賒青簡，封章窒皂囊。',12,'全唐诗/poet.song.178000.json','["信史賒青簡，封章窒皂囊。"]'),
('4bbab977-f470-4b8e-a788-b41881d20104','留題頂山上方','程準','宋','宋诗','song-poetry','','[]','雨歇黄梅後，秋生麥熟前。',48,'全唐诗/poet.song.178000.json','["雨歇黄梅後，秋生麥熟前。", "偶同金馬客，來訪玉龍泉。", "竹葉一樽酒，榴花五月天。", "不妨扶拄杖，行到白雲邊。"]'),
('6a9d913a-3693-4bb8-a227-a0dab47bb0b2','明遠樓','程準','宋','宋诗','song-poetry','','[]','帆带暮雲歸別浦，崖拖秋色落澄波。',32,'全唐诗/poet.song.178000.json','["帆带暮雲歸別浦，崖拖秋色落澄波。", "天連尺五銀河挽，月倍尋常玉鏡磨。"]'),
('2d54ae43-5294-4eaa-9d43-5f9ec873895f','浮丘祠','鄭晦','宋','宋诗','song-poetry','','[]','青天志欲騎長虹，半生雙眼四海空。',204,'全唐诗/poet.song.178000.json','["青天志欲騎長虹，半生雙眼四海空。", "題詩遠寄廣成子，筆力萬仞摇崆峒。", "前年鶴背乘天風，翻然回首江之東。", "束書歸隠黄山中，山中偶遇浮丘翁。", "人生寰宇總過客，呼酒澆愁醉李白。", "十畝耕雲種紫芝，酣歌擊石嫌春窄。", "招浮丘，乾坤到處堪遨遊。", "丈夫有志身徇國，逢時無意干封侯。", "皇天恩澤盈遐陬，忍視吳楚森戈矛。", "黄金白璧豈足尚，我愛文章有官樣。", "長篇欲向庵壁題，憑陵豪氣三千丈。", "住庵道人請書壁，禿毫轟雷停不得。", "飛香灑雪淋漓濕，一夜寒風瘦蛟泣。"]'),
('90d24840-d3c3-493b-8189-723472de3610','題常樂寺五雲臺','姚舜陟','宋','宋诗','song-poetry','','[]','虛空本無雲，一氣誰所主。',120,'全唐诗/poet.song.178000.json','["虛空本無雲，一氣誰所主。", "雲空兩無礙，起滅自散聚。", "吾聞心歸源，空殞亦無所。", "應知不空者，物感自如雨。", "君看賢首師，自視木與土。", "與雲亦奚期，況問色有五。", "云何坐說法，瑞應乃如許。", "休疑諸天集，未必衆龍吐。", "雲空法如是，我說無說故。", "堂中嫡孫在，客至當問取。"]'),
('5a1ec2ea-9d43-406f-bc6b-b3ad392f96c7','楊高士聽彈琴','姚舜陟','宋','宋诗','song-poetry','','[]','我來請雨謁龍公，日脚已歛雲沖融。',176,'全唐诗/poet.song.178000.json','["我來請雨謁龍公，日脚已歛雲沖融。", "解衣盤礴暫小憇，清談對此兩相翁。", "霏霏鋸屑引意靜，爇鼎忽聞彈絲桐。", "少年水師貌頗古，十指捲袖如剝葱。", "初爲宮聲變羽調，雅澹更覺神雍容。", "是時晝晷屋角轉，洶湧萬木鳴西風。", "吹蟬得志競清嘯，恍異人境如天宮。", "茲山頗疑洞府外，地有奇石皆玲瓏。", "是何美韵愜振玉，意欲直造無何中。", "塵埃自嘆百僚底，誰謂一日欣遭逢。", "更須霖雨起焦旱，茲遊可記傳無窮。"]'),
('8c61b191-ca19-4a97-8682-8a50dcf03bbf','送蓋少卿晞之赴太平州','衛涇','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','三釜果何樂，萬鍾豈云輕。',288,'全唐诗/poet.song.178000.json','["三釜果何樂，萬鍾豈云輕。", "當知昔賢士，及親乃爲榮。", "憶昨使東淮，循陔蘭芳馨。", "維先司徒公，大篇寵其行。", "喜我諧祿養，勸之力身名。", "俛仰四十載，歲月何崢嶸。", "髯卿世濟美，中外稔踐更。", "勇退甫宴娛，起家俄詔徵。", "秩真二千石，選授參陪京。", "時哉春陽中，光風助嚴程。", "歌廉盛襦袴，迎伋森旆旌。", "矧伊太夫人，九十顔如嬰。", "朱轓從板輿，此樂誰能并。", "緬懷平生好，相友真弟兄。", "我今抱永慕，撫舊祇愴情。", "塗山古名邦，官府號太平。", "故秋適淫潦，所至多疲氓。", "政須事安集，未可施敲榜。", "長江戍水犀，形勢足干城。", "時雖急規恢，不用邀功能。", "君年壯於我，宏圖在南溟。", "報國豈憂晚，事親宜竭誠。", "道院日餘暇，北堂慶方增。", "戲綵供笑粲，捧觴壽期齡。"]'),
('bf2ed81c-ebfe-44e7-b2d8-36691e44b877','張德輝以詩見遺需酒因次韵解嘲','衛涇','宋','宋诗','song-poetry','','[]','廷評一石了獄事，謫仙一斗百篇詩。',64,'全唐诗/poet.song.178000.json','["廷評一石了獄事，謫仙一斗百篇詩。", "君才盤盤壓今古，肯使英名誇昔時。", "濁醪妙理清有聖，此意豈復達士疑。", "我慚鼷腹怯鯨量，咄咄隠几成書癡。"]'),
('45e415cb-4be9-4ad4-b6bb-cd89ee9bb189','舟行遇順風','衛涇','宋','宋诗','song-poetry','','[]','畫船昨日吳江西，風雨滿江鼓棹遲。',96,'全唐诗/poet.song.178000.json','["畫船昨日吳江西，風雨滿江鼓棹遲。", "客帆過眼撇波去，坐看舟子相猶夷。", "今朝風忽發東北，縱帆如飛揭百尺。", "來者寸步不可前，停艫悵望求弗獲。", "風從何來天何爲，順喜逆怨人自私。", "世間萬事亦爾耳，乘除妙理君安知。"]'),
('c79f7a60-2bda-40dd-be6a-141b954d02cf','呈張德輝','衛涇','宋','宋诗','song-poetry','','[]','韞櫝君子藏，枉尋吾道曲。',52,'全唐诗/poet.song.178000.json','["韞櫝君子藏，枉尋吾道曲。", "絕物忌太清，狥世未免俗。", "人言俗難醫，我見清可濯。", "安得直上挽天河，一洗俗塵千萬斛。"]'),
('e3bd55b8-0406-4afb-8db8-6fc227f86cbb','爲楊仲起壽','衛涇','宋','宋诗','song-poetry','','[]','天台高壓東南州，秀鍾千古生公侯。',168,'全唐诗/poet.song.178000.json','["天台高壓東南州，秀鍾千古生公侯。", "君才槃槃第一流，學優顔閔卑由求。", "天意端爲斯文憂，妙齡掉鞅從英游。", "筆力挽强回萬牛，金玉精美價未酬。", "文章從古天地讐，演起大業難延留。", "騰驤萬里須騏騮，行看大對悟凝旒。", "擢冠多士騎鰲頭，歸來雙親喜氣浮，充閭佳瑞樂事修。", "煙霄衮衮殊未休，整頓乾坤攄壯猷。", "策勳稷契伊呂周，請公爲酬白玉舟。", "他年名遂高千秋，却揖劉阮尋浮邱。"]'),
('d4e93a7a-9f5f-4dc4-9b3c-d018e749ace7','上親庭壽','衛涇','宋','宋诗','song-poetry','','[]','中興申甫來高崧，卜人吉夢占維熊。',216,'全唐诗/poet.song.178000.json','["中興申甫來高崧，卜人吉夢占維熊。", "生賢應有造化工，吾家積善慶所鍾。", "公跨鸞馭從蓬宮，襟懷廓落凌秋空。", "居鄉惠愛先困窮，譚笑萬戶生春融。", "在官履行潔且忠，此心須信天可通。", "福善有道非濫蒙，歲寒乃知柏與松。", "從今風虎依雲龍，扶摇萬里乘長風。", "結知丹扆恩厖鴻，金貂赤舄華吾宗。", "尊榮安壽仁之功，從教綠鬢宜方瞳。", "義方垂教慚倥侗，青氈欲使揚祖風。", "勉策駑駕追逸蹤，它年樂事來迎逢。", "燕山嘉譽難獨隆，宴堂清曉祥雲濃，槐庭晝永陰重重。", "千歲風月誰與同，敬祝王母偕僊翁。"]'),
('7993c23a-516b-423d-b0b0-749a10b97411','元日到湖上','衛涇','宋','宋诗','song-poetry','','[]','勳業須年少，棲遲祇自憐。',48,'全唐诗/poet.song.178000.json','["勳業須年少，棲遲祇自憐。", "若爲車阨首，未試翼垂天。", "拭目看新歷，傷心惜去年。", "湖山一舒嘯，春信滿梅邊。"]'),
('5f73e98c-4365-447d-829d-42b404cf6f7c','次德茂沌中韵','衛涇','宋','宋诗','song-poetry','','[]','沌路隨江轉，疎籬匝岸斜。',48,'全唐诗/poet.song.178000.json','["沌路隨江轉，疎籬匝岸斜。", "寄身千萬里，慰眼兩三家。", "老矣思爲圃，歸歟學種瓜。", "遥知荷鋤倦，一酌散腰麻。"]'),
('0d72493b-d6e9-4073-85f1-9cde63b73abc','挽高宗皇帝章四首  其一','衛涇','宋','宋诗','song-poetry','','[]','大業高千古，斯文炳六經。',48,'全唐诗/poet.song.178000.json','["大業高千古，斯文炳六經。", "無刑深帝澤，不戰壽生靈。", "神聖非殂落，乾坤有晦冥。", "難名是天德，刻畫謾丹青。"]'),
('59f90541-f67d-40ab-b29e-78943bcfabcc','挽高宗皇帝章四首  其二','衛涇','宋','宋诗','song-poetry','','[]','致治勤三紀，怡神壽九齡。',48,'全唐诗/poet.song.178000.json','["致治勤三紀，怡神壽九齡。", "玉巵傳漢殿，寶冊煥堯庭。", "慶事方頻舉，哀歌詎忍聽。", "萬邦惟戴舜，億載奉慈寧。"]'),
('39aed631-e63d-46e3-a06b-6cb2ca34c3c4','挽高宗皇帝章四首  其三','衛涇','宋','宋诗','song-poetry','','[]','歷數千齡在，謳歌四海歸。',48,'全唐诗/poet.song.178000.json','["歷數千齡在，謳歌四海歸。", "地雄元帥府，天授上皇衣。", "洗甲乾坤凈，投戈日月揮。", "成功有如此，今古獨巍巍。"]'),
('5247de63-3c99-4c05-9bb1-dde93766ca42','挽高宗皇帝章四首  其四','衛涇','宋','宋诗','song-poetry','','[]','江右龍飛後，臨安日暈時。',48,'全唐诗/poet.song.178000.json','["江右龍飛後，臨安日暈時。", "煌煌周禮樂，肅肅漢威儀。", "魚水君臣會，耕桑父子嬉。", "誰歟老文學，重述中興碑。"]'),
('8cc930a6-a0d1-4189-ab23-1d89a1c56a66','悼外姑安康郡太夫人章氏  其一','衛涇','宋','宋诗','song-poetry','','[]','有美夫人德，家齊周召來。',48,'全唐诗/poet.song.178000.json','["有美夫人德，家齊周召來。", "義襟賙梓里，孝養備蘭陔。", "爵視三槐貴，年登九袠開。", "追榮知未艾，卿月近公台。"]'),
('1d40517e-fc9d-4672-a598-78c122cdd05d','悼外姑安康郡太夫人章氏  其二','衛涇','宋','宋诗','song-poetry','','[]','鷄犬相聞地，湖山百里間。',48,'全唐诗/poet.song.178000.json','["鷄犬相聞地，湖山百里間。", "自憐同子姓，無復恃慈顔。", "薤露聲徒切，靈輀去不還。", "擬爲臨穴慟，哀淚已潸潸。"]'),
('07f64dc6-639f-4d98-9a7b-15f2b1d9d4ed','悼倪尚書  其一','衛涇','宋','宋诗','song-poetry','','[]','歷事三朝久，清居一世尊。',48,'全唐诗/poet.song.178000.json','["歷事三朝久，清居一世尊。", "心惟在王室，手不炙權門。", "橫浦流風好，香山逸興存。", "經綸未渠展，此意向誰論。"]'),
('a4a29a56-a0b8-453b-84b8-4da66d8fd646','悼倪尚書  其二','衛涇','宋','宋诗','song-poetry','','[]','舊草揚庭制，旋高曳履聲。',48,'全唐诗/poet.song.178000.json','["舊草揚庭制，旋高曳履聲。", "胸襟忠憤切，官職去留輕。", "定力鰲爲動，浮言蜮自鳴。", "太玄從白首，性地轉分明。"]'),
('8dd0906e-7d08-4357-94bd-eee618e4468a','悼倪尚書  其三','衛涇','宋','宋诗','song-poetry','','[]','入館論心舊，同朝託契長。',48,'全唐诗/poet.song.178000.json','["入館論心舊，同朝託契長。", "鱸鄉各歸去，鷗水久相忘。", "正喜山中隠，俄傳橘裏藏。", "遺銘最奇絕，讀罷淚淋浪。"]'),
('d50b1775-427f-4a6a-bda9-1644940e6351','長沙鹿鳴宴送諸進士','衛涇','宋','宋诗','song-poetry','','[]','楚材從古擅豪雄，况是長沙世著忠。',64,'全唐诗/poet.song.178000.json','["楚材從古擅豪雄，况是長沙世著忠。", "鳴鹿三章新得句，摶鵬萬里穩摩空。", "科名直寄文詞表，事業相期氣節中。", "畎畝平時憂國念，盍將長策沃宸衷。"]'),
('c2f426b9-b83d-41a6-9e08-0acf13c52e05','上皇太子壽  其一','衛涇','宋','宋诗','song-poetry','','[]','嘉辰鷄戟瑞煙高，蒼震丕承九廟祧。',64,'全唐诗/poet.song.178000.json','["嘉辰鷄戟瑞煙高，蒼震丕承九廟祧。", "潮駕天吳彰海潤，氣涵雲漢毓金昭。", "分陰資善時稽古，辨色含元日侍朝。", "欲識斯心仁壽處，謨參聖父五兵銷。"]'),
('eec99cde-828a-487d-9145-6370aeae472c','上皇太子壽  其二','衛涇','宋','宋诗','song-poetry','','[]','南極秋中夜有輝，經旬先與玉衡齊。',64,'全唐诗/poet.song.178000.json','["南極秋中夜有輝，經旬先與玉衡齊。", "祥開遊震天方眷，德懋元良日自躋。", "風爽銅聲諧戶御，月明銀鏤濕宮題。", "遥知侍宴歡魚藻，曾忝賓筵漫舞醯。"]'),
('dff51d96-5ba5-4e14-8807-949007d59387','爲樂提刑壽二首  其一','衛涇','宋','宋诗','song-poetry','','[]','千里瀟湘秋氣清，使星高並壽星明。',64,'全唐诗/poet.song.178000.json','["千里瀟湘秋氣清，使星高並壽星明。", "雲槎端向銀河上，仙桂真從璧月生。", "好善優優樂正子，騰光焰焰李長庚。", "會看初度稱觴後，徑駕鋒車入帝城。"]'),
('93d2bb3c-a963-4235-9829-65e1e659f604','爲樂提刑壽二首  其二','衛涇','宋','宋诗','song-poetry','','[]','繡衣持斧按蠻荆，三見門弧喜氣盈。',64,'全唐诗/poet.song.178000.json','["繡衣持斧按蠻荆，三見門弧喜氣盈。", "孟子能令棠粟發，不疑更使漢刑平。", "好將兩手摩銅狄，長對三秋正玉衡。", "聞道中宵思賈傅，江湖未可老鱣鯨。"]'),
('3d112d32-fd34-4d9f-9fb9-d61b7702d4a2','爲運使蔡國博壽二首  其一','衛涇','宋','宋诗','song-poetry','','[]','橘顆圍僊飽紫芝，菊潭釀酒拍金巵。',64,'全唐诗/poet.song.178000.json','["橘顆圍僊飽紫芝，菊潭釀酒拍金巵。", "九秋沆碭成功日，六轡光華初度時。", "試問江湖勞漕輓，何如朝夕密論思。", "預知來歲生朝後，更著宮袍拜赤墀。"]'),
('448d9911-a701-4c20-9fbf-1ada429b8420','爲運使蔡國博壽二首  其二','衛涇','宋','宋诗','song-poetry','','[]','西山南浦氣葱葱，夜擁長庚粲碧空。',64,'全唐诗/poet.song.178000.json','["西山南浦氣葱葱，夜擁長庚粲碧空。", "惠露昔霑江漢表，使星今照斗牛中。", "晚粳已喜霜前熟，宿麥應從雨後豐。", "十一州人還得飽，繡衣壽斚與民同。"]'),
('75cb29f8-1749-4040-ba6c-cbc32ddb439a','古林邱','衛涇','宋','宋诗','song-poetry','','[]','支筇來訪古林邱，轉盡山腰俯碧流。',64,'全唐诗/poet.song.178000.json','["支筇來訪古林邱，轉盡山腰俯碧流。", "峭壁千尋懸石磴，蒼崖百尺護龍湫。", "行人跡斷煙常暝，過鳥聲閑意更幽。", "小憩已銷塵俗慮，溪山奇絕是茲遊。"]'),
('149c6e3b-58d9-4d41-b9c8-f39912816717','晚晴','衛涇','宋','宋诗','song-poetry','','[]','雨斷風回忽報晴，山顛初日掛銅鉦。',64,'全唐诗/poet.song.178000.json','["雨斷風回忽報晴，山顛初日掛銅鉦。", "雲烟藏迹千峰翠，草木增華兩眼明。", "桑野枝空蠶杼歇，溪泉溜急水車鳴。", "鳥啼花笑渾如喜，此去山齋只一程。"]'),
('5a626145-e3fb-421d-a9ca-6bb97c8d1083','沈氏書堂','衛涇','宋','宋诗','song-poetry','','[]','東山風景壓東吳，更築書堂映碧梧。',64,'全唐诗/poet.song.178000.json','["東山風景壓東吳，更築書堂映碧梧。", "詹尹詩存家有寶，齊齋記外更無圖。", "洗除紈袴爲緗帙，掃蕩膏粱入澤臞。", "早晚歸舟行霅上，青燈深夜聽伊吾。"]'),
('1b603846-22e2-4a8f-8302-c33b1b7c8009','五日子刻立春','衛涇','宋','宋诗','song-poetry','','[]','客中春到不知春，庭草青青入眼新。',64,'全唐诗/poet.song.178000.json','["客中春到不知春，庭草青青入眼新。", "對酒可無人作伴，照書却有雪爲隣。", "雕盤玉笋傳生菜，寶勝金花錫近臣。", "我已棲遲寧事事，有誰曾爲嘆長貧。"]'),
('24b44b8a-2e3f-4dcb-8581-da7fc4f39b54','次德茂用惟直南樓韵','衛涇','宋','宋诗','song-poetry','','[]','眼明仍見大江浮，貪看青山倚柂樓。',64,'全唐诗/poet.song.178000.json','["眼明仍見大江浮，貪看青山倚柂樓。", "落日鷄豚秋保社，輕風蘋蓼晚汀洲。", "長征倦馬思夷路，不下驚鷗避急流。", "亦有琅玕何所贈，漫歌平子側身愁。"]'),
('6da071a4-9edc-4d0a-a009-c577a38a1488','山行後觀及通鑑五代之際成敗得喪廢興之跡因爲感慨用前韵','衛涇','宋','宋诗','song-poetry','','[]','溪山適興且閑行，綠蘚蒼苔任點裳。',64,'全唐诗/poet.song.178000.json','["溪山適興且閑行，綠蘚蒼苔任點裳。", "看鏡已侵雙鬢碧，憂時每覺寸心傷。", "馳名擾擾終安用，浩飲陶陶計亦長。", "千古英雄誰可問，纍纍邱隴水茫茫。"]'),
('5a06f82e-9830-4088-8045-82e1a87d08af','次韵呈與叔兄','衛涇','宋','宋诗','song-poetry','','[]','野塘古岸飽經行，風雨塵埃笑滿裳。',64,'全唐诗/poet.song.178000.json','["野塘古岸飽經行，風雨塵埃笑滿裳。", "尊酒清江君意厚，片帆千里客懷傷。", "出門求益謀何拙，掃几觀書味更長。", "歸去飛篷試回首，一川煙水正微茫。"]'),
('77d3184d-cbcb-4703-9e99-0725eefc3b27','次韵高仲貽贈別','衛涇','宋','宋诗','song-poetry','','[]','金椀輕拋入釣船，夜寒侵被不成眠。',64,'全唐诗/poet.song.178000.json','["金椀輕拋入釣船，夜寒侵被不成眠。", "近傳奏疏三千牘，今見新詩十二篇。", "故國音書憑過鴈，江城烽火照晴天。", "移舟鐵甕城邊去，信與名山舊有緣。"]'),
('850e99c9-6651-4069-83bb-5744ed2469c1','月夜登吳江垂虹','衛涇','宋','宋诗','song-poetry','','[]','平湖萬頃天無風，試上垂虹月滿空。',64,'全唐诗/poet.song.178000.json','["平湖萬頃天無風，試上垂虹月滿空。", "豁目直窮煙障外，諸峰渾出有無中。", "混同天地纖塵絕，倒影星辰萬象雄。", "却笑三山遊汗漫，恍然身世到蓬宮。"]'),
('4139162a-46c9-4a91-a753-4364f71267c5','爲師席李上舍去智壽四首  其一','衛涇','宋','宋诗','song-poetry','','[]','當時騎氣擁函關，奕代清才擅謫仙。',32,'全唐诗/poet.song.178000.json','["當時騎氣擁函關，奕代清才擅謫仙。", "鼻祖嬋嫣有餘慶，至今名世更生賢。"]'),
('2077b01b-6952-447a-81cb-36bcf5dc2442','爲師席李上舍去智壽四首  其二','衛涇','宋','宋诗','song-poetry','','[]','屢將大手占倫魁，槐市英聲早四馳。',32,'全唐诗/poet.song.178000.json','["屢將大手占倫魁，槐市英聲早四馳。", "肯與鱣魴爭尺水，鵾鵬行矣化天池。"]'),
('39f2597b-3873-4308-9ac8-c06c0de1dba6','爲師席李上舍去智壽四首  其三','衛涇','宋','宋诗','song-poetry','','[]','道義須知耐歲寒，論心還喜臭如蘭。',32,'全唐诗/poet.song.178000.json','["道義須知耐歲寒，論心還喜臭如蘭。", "龍鱗幸許同攀附，乞與春風借羽翰。"]'),
('578482f6-724f-4515-ba57-2e7852c9f7cb','爲師席李上舍去智壽四首  其四','衛涇','宋','宋诗','song-poetry','','[]','美景良辰幸與同，瓣香聊以祝南豐。',32,'全唐诗/poet.song.178000.json','["美景良辰幸與同，瓣香聊以祝南豐。", "它年妙斡洪鈞手，盡納羣生壽域中。"]'),
('1c0a0d97-b4df-4612-947b-40ae7d9e22be','夜坐','衛涇','宋','宋诗','song-poetry','','[]','深山五月清無暑，露氣漙空午夜寒。',32,'全唐诗/poet.song.178000.json','["深山五月清無暑，露氣漙空午夜寒。", "草際鳴蛩更强聒，滿懷秋思寄毫端。"]'),
('94c72698-7511-48b6-8024-c607f88a2d5f','次與叔兄山行韵','衛涇','宋','宋诗','song-poetry','','[]','陰雲凍合不成飛，行李留連歲律遲。',32,'全唐诗/poet.song.178000.json','["陰雲凍合不成飛，行李留連歲律遲。", "山色宜晴更宜雪，別來應有憶山詩。"]'),
('1545ed9e-3707-4ba4-8e31-88954c2c5f02','與進叔弟策杖山行遣馬還孫氏','衛涇','宋','宋诗','song-poetry','','[]','掣電追風古見稱，駑材空負渥洼名。',32,'全唐诗/poet.song.178000.json','["掣電追風古見稱，駑材空負渥洼名。", "何如手植青藜杖，雲屨風裾自在行。"]'),
('df972305-ef2a-4624-8879-23f067d17a38','登寺中蕭疎極甚不見一僧獨坐雲堂數刻口占','衛涇','宋','宋诗','song-poetry','','[]','蕭條古寺僧何處，癡坐方床午漏長。',32,'全唐诗/poet.song.178000.json','["蕭條古寺僧何處，癡坐方床午漏長。", "怪我溪山慣來往，不惟魚鳥解相忘。"]'),
('2d19cc47-f072-4d2c-b225-1cc157ebb30c','張巖拙軒窯寺用壁韵','衛涇','宋','宋诗','song-poetry','','[]','幾陣涼風清不盡，一天秋色渺無邊。',32,'全唐诗/poet.song.178000.json','["幾陣涼風清不盡，一天秋色渺無邊。", "僧房好處閒窗牖，把定山椒紫翠煙。"]'),
('cc895ece-5579-4da0-a35a-d19563705a25','別吳荆溪  其一','衛涇','宋','宋诗','song-poetry','','[]','八載江湖甫召還，深言應又忤天顔。',32,'全唐诗/poet.song.178000.json','["八載江湖甫召還，深言應又忤天顔。", "九重不見饑民色，只看先生兩鬢間。"]'),
('7768baf5-82bb-4130-907f-92d7291f13ae','別吳荆溪  其二','衛涇','宋','宋诗','song-poetry','','[]','去年靈麓未空寒，一客南歸不足歎。',32,'全唐诗/poet.song.178000.json','["去年靈麓未空寒，一客南歸不足歎。", "學子今翻辭使旆，歸來只得片碑看。"]'),
('b8cc88c3-1698-4490-a564-d059da3f3a7a','別吳荆溪  其三','衛涇','宋','宋诗','song-poetry','','[]','家數文章有路尋，雲韶殊世不殊音。',32,'全唐诗/poet.song.178000.json','["家數文章有路尋，雲韶殊世不殊音。", "小生不幸生來晚，纔識先生識水心。"]'),
('b1ec3e63-4858-462f-b823-f0f1e77952da','金鰻井','衛涇','宋','宋诗','song-poetry','','[]','鰻井由來歲月深，泓澄一鏡絕塵侵。',32,'全唐诗/poet.song.178000.json','["鰻井由來歲月深，泓澄一鏡絕塵侵。", "要觀變化神功妙，會見翻爲旱歲霖。"]'),
('fc9efd12-2712-4a11-935e-c3daf87153f5','開化寺前古木數株葉密陰繁極可愛繫舟其下賦此','衛涇','宋','宋诗','song-poetry','','[]','古木蒼然幾歲周，摩空老幹蔭溪流。',32,'全唐诗/poet.song.178000.json','["古木蒼然幾歲周，摩空老幹蔭溪流。", "舉頭未見征帆下，來向清陰繫小舟。"]'),
('07a5af4a-b781-4bba-ad37-616dedaa023f','憶環谷古梅  其一','衛涇','宋','宋诗','song-poetry','','[]','百花頭上春光到，雪壓霜欺意更奇。',32,'全唐诗/poet.song.178000.json','["百花頭上春光到，雪壓霜欺意更奇。", "歲歲倚欄相望處，水邊竹外最南枝。"]'),
('c269f9d7-9ef1-4ea8-acff-2b3d13f1e22a','憶環谷古梅  其二','衛涇','宋','宋诗','song-poetry','','[]','故園一別換年華，客裏看花更憶花。',32,'全唐诗/poet.song.178000.json','["故園一別換年華，客裏看花更憶花。", "昨夜西窗無限月，伴人春瘦一枝斜。"]'),
('80543bfe-f70c-44df-88d3-b74f9e9d49ca','小山遊翠峰寺携枕席寄宿僧堂僧甚多而不與人相接戲成','衛涇','宋','宋诗','song-poetry','','[]','癡坐禪關日亭午，靜看博山香一縷。',32,'全唐诗/poet.song.178000.json','["癡坐禪關日亭午，靜看博山香一縷。", "欲知世上炎與涼，三扣金僊三不語。"]'),
('1f961062-15b6-4624-b48f-11c7137db92f','欲至浙江送子寔聞潮早不果行小詩寄別','衛涇','宋','宋诗','song-poetry','','[]','尊酒清江欲語離，事多八九苦參差。',32,'全唐诗/poet.song.178000.json','["尊酒清江欲語離，事多八九苦參差。", "飛潮更捲征帆急，盡作西窗去後思。"]'),
('80b3876a-b254-4f69-bc89-5fa4f7ee4f07','聞和叔撫琴','衛涇','宋','宋诗','song-poetry','','[]','蓐收傳令待殘更，斗轉參橫露氣清。',32,'全唐诗/poet.song.178000.json','["蓐收傳令待殘更，斗轉參橫露氣清。", "誰弄瑶池三尺玉，怪來萬壑動秋聲。"]'),
('0da797b4-d51a-4318-9933-a84b1062060a','皇帝閤春帖子  其一','衛涇','宋','宋诗','song-poetry','','[]','芳意傳梅信，東風到柳邊。',24,'全唐诗/poet.song.178000.json','["芳意傳梅信，東風到柳邊。", "王春在除夜，明日是新年。"]'),
('3a6f1749-84bf-4cff-9753-7b04e0da7e7b','皇帝閤春帖子  其二','衛涇','宋','宋诗','song-poetry','','[]','綵勝黄金縷，青絲白玉盤。',24,'全唐诗/poet.song.178000.json','["綵勝黄金縷，青絲白玉盤。", "內家迎淑節，先奉太皇歡。"]'),
('315573cb-e500-4969-939b-e68c9822ec9f','皇帝閤春帖子  其三','衛涇','宋','宋诗','song-poetry','','[]','遲明魚鑰九門開，警蹕聲清繞殿雷。',32,'全唐诗/poet.song.178000.json','["遲明魚鑰九門開，警蹕聲清繞殿雷。", "穆穆天顔應有喜，捷書新自北邊來。"]'),
('3d007411-2c64-4b5a-a5eb-31bce41077a9','皇帝閤春帖子  其四','衛涇','宋','宋诗','song-poetry','','[]','沈沈廣殿靡遑安，玉食丁寧減太官。',32,'全唐诗/poet.song.178000.json','["沈沈廣殿靡遑安，玉食丁寧減太官。", "野宿貔貅三萬竈，重裘應軫鐵衣寒。"]'),
('17bea9c5-7a9b-4e53-9150-4fe13ae9cfc5','壽成惠聖慈祐太皇太后閤春帖子  其一','衛涇','宋','宋诗','song-poetry','','[]','一德坤元厚，三朝母道尊。',24,'全唐诗/poet.song.178000.json','["一德坤元厚，三朝母道尊。", "含飴供樂事，戲綵見重孫。"]'),
('482dd2fd-be70-4fe2-88b3-c26c53bc966b','壽成惠聖慈祐太皇太后閤春帖子  其二','衛涇','宋','宋诗','song-poetry','','[]','北內風光別，僊家日月閑。',24,'全唐诗/poet.song.178000.json','["北內風光別，僊家日月閑。", "紫皇天下養，金母住人間。"]'),
('deba1b4d-d943-48b5-ba83-da4c17354842','壽成惠聖慈祐太皇太后閤春帖子  其三','衛涇','宋','宋诗','song-poetry','','[]','柳色侵宮瓦，花陰覆綺疏。',24,'全唐诗/poet.song.178000.json','["柳色侵宮瓦，花陰覆綺疏。", "鵲爐煙馥郁，賸閲妙乘書。"]'),
('29c6145f-5a14-41db-b1e0-8718d507db51','壽成惠聖慈祐太皇太后閤春帖子  其四','衛涇','宋','宋诗','song-poetry','','[]','銀旛點綴鬭宮嬪，小字橫斜篆縷新。',32,'全唐诗/poet.song.178000.json','["銀旛點綴鬭宮嬪，小字橫斜篆縷新。", "歲歲詞臣供帖子，從今便數八千春。"]'),
('a1464fa1-2967-4c28-a1e6-e8ed0049aa74','壽成惠聖慈祐太皇太后閤春帖子  其五','衛涇','宋','宋诗','song-poetry','','[]','文孫親上萬年巵，姒婦嚴粧五翟衣。',32,'全唐诗/poet.song.178000.json','["文孫親上萬年巵，姒婦嚴粧五翟衣。", "不用都人須數蹕，內庭跬步即重闈。"]'),
('f0435b3c-9ac0-4584-b881-fa40fc59e317','壽成惠聖慈祐太皇太后閤春帖子  其六','衛涇','宋','宋诗','song-poetry','','[]','刁斗轅門五夜深，思齊文母正關心。',32,'全唐诗/poet.song.178000.json','["刁斗轅門五夜深，思齊文母正關心。", "身臨大練無他費，湯沐先捐鉅萬金。"]'),
('f65be752-e788-404e-b092-8077ccf2bf12','皇帝閤端午帖子  其一','衛涇','宋','宋诗','song-poetry','','[]','五日天中候，南風物阜時。',24,'全唐诗/poet.song.178000.json','["五日天中候，南風物阜時。", "三邊寬大詔，億載太平期。"]'),
('d0c83e52-f859-41b9-878a-674f78983ac1','皇帝閤端午帖子  其二','衛涇','宋','宋诗','song-poetry','','[]','御服齊官獻，生衣暴室供。',24,'全唐诗/poet.song.178000.json','["御服齊官獻，生衣暴室供。", "金箱初進入，一一耀黄封。"]'),
('3fe9c563-7f1a-46b9-9cf3-125d1690a6ca','皇帝閤端午帖子  其三','衛涇','宋','宋诗','song-poetry','','[]','日轂亭午，金徒緩報衙。',23,'全唐诗/poet.song.178000.json','["日轂亭午，金徒緩報衙。", "邇英催晚講，分賜壑源茶。"]'),
('be21bab7-1a15-41c2-836d-50e515151611','皇帝閤端午帖子  其四','衛涇','宋','宋诗','song-poetry','','[]','靈開玉壘靜無塵，聖澤新覃雨露勻。',32,'全唐诗/poet.song.178000.json','["靈開玉壘靜無塵，聖澤新覃雨露勻。", "束縛仇頭藏武庫，梟羹不用賜羣臣。"]'),
('dba6c4aa-fc81-480f-81e3-e645818e2b71','皇帝閤端午帖子  其五','衛涇','宋','宋诗','song-poetry','','[]','遠人新有約和書，並塞狼煙指日無。',32,'全唐诗/poet.song.178000.json','["遠人新有約和書，並塞狼煙指日無。", "聖主憂民軫宵旰，宮中猶綰辟兵繻。"]'),
('4cd53030-f859-4abb-8f90-40b63430a931','壽成惠聖慈祐太皇太后閤端午帖子  其一','衛涇','宋','宋诗','song-poetry','','[]','清禁傳呼近，紅雲擁紫皇。',24,'全唐诗/poet.song.178000.json','["清禁傳呼近，紅雲擁紫皇。", "菖花浮九醖，請祝壽無疆。"]'),
('02ca16a9-9bbd-4499-ad43-88742dfff0ba','壽成惠聖慈祐太皇太后閤端午帖子  其二','衛涇','宋','宋诗','song-poetry','','[]','邊頭傳吉語，井絡報平安。',24,'全唐诗/poet.song.178000.json','["邊頭傳吉語，井絡報平安。", "今歲端辰別，慈顔一笑歡。"]'),
('3ba9d6cb-4dc4-4ac1-b9be-0126c60d0de6','壽成惠聖慈祐太皇太后閤端午帖子  其三','衛涇','宋','宋诗','song-poetry','','[]','綵縷新纏臂，靈符穩插釵。',24,'全唐诗/poet.song.178000.json','["綵縷新纏臂，靈符穩插釵。", "承平多舊事，閑教小宮娃。"]'),
('9a6e9f4e-564a-44a7-8a1b-ad7fb4d35895','壽成惠聖慈祐太皇太后閤端午帖子  其四','衛涇','宋','宋诗','song-poetry','','[]','雙人翠艾垂朱戶，三角瓊糜護箬衣。',32,'全唐诗/poet.song.178000.json','["雙人翠艾垂朱戶，三角瓊糜護箬衣。", "聞道內家行樂祕，先將節物奉重闈。"]'),
('2e5e6033-4cbd-441d-a9d6-79de653ec1ab','壽成惠聖慈祐太皇太后閤端午帖子  其五','衛涇','宋','宋诗','song-poetry','','[]','深宮永日鎮長閑，心靜多繙蘂笈篇。',32,'全唐诗/poet.song.178000.json','["深宮永日鎮長閑，心靜多繙蘂笈篇。", "侍女身留香案側，旋燔金餠炷爐煙。"]'),
('9fffb5c8-0dfc-4a39-8572-2c116ae6ea0b','壽成惠聖慈祐太皇太后閤端午帖子  其六','衛涇','宋','宋诗','song-poetry','','[]','人間無處避炎蒸，身在瑶臺最上層。',32,'全唐诗/poet.song.178000.json','["人間無處避炎蒸，身在瑶臺最上層。", "學士大書金字帖，宮中巧篆絳綃繒。"]'),
('2e55ec93-41d6-4d5a-a45c-b137f547ce01','遊澱湖','衛涇','宋','宋诗','song-poetry','','[]','疎星殘月尚朦朧，閑趁烟波一棹風。',64,'全唐诗/poet.song.178000.json','["疎星殘月尚朦朧，閑趁烟波一棹風。", "始覺舟移楊柳岸，直疑身到水晶宮。", "鳥鴉天際墨千點，白鷺灘頭玉一叢。", "欵乃一聲回首處，西山橫在有無中。"]'),
('71756fba-d59a-4200-8e85-5f451c26ddf2','雲山歌','徐僑','宋','宋诗','song-poetry','','[]','雲山窈兮風微，山徑繚兮雲依。',143,'全唐诗/poet.song.178000.json','["雲山窈兮風微，山徑繚兮雲依。", "蘭馨兮晨晞，松樛兮夕暉。", "有禽消摇其間兮不去，飛俛啄兮蔌薇。", "昂吟兮綠筠枝，春與鼯騰兮秋鶑與啼。", "希鸞鵠兮志亦幾，絕樊弋兮隨所棲。", "空碧臨臨兮山四圍，泉咽咽兮流以時。", "寧易地兮潁若箕，與世相忘兮幽人期。", "山雖高兮步坦夷，雲雖深兮光陸離。", "胸洞洞兮陶然以怡，祗天命兮安厥宜。"]'),
('466db717-fa05-4d8f-9acd-3f99d2e2b652','行行歌','徐僑','宋','宋诗','song-poetry','','[]','行行兮何之，郊之疇兮山之徑。',125,'全唐诗/poet.song.178000.json','["行行兮何之，郊之疇兮山之徑。", "耕藝兮雨晴，樵牧兮昕暝。", "室廬兮其倫，老稚兮其性。", "負者蹇兮趨者勁，役而歌兮遊以詠。", "機杼兮國資，雞犬兮家政。", "草萋萋其青兮，木蔚蔚其盛。", "吭林鳴兮尾川泳，空雲騰兮月出嶺。", "威之霜兮風以令，胡然而然兮。", "森森兮天之命，職我其間兮毋不敬。"]'),
('14e9207c-1a5a-474c-84ea-20c789a5082e','常自在歌','徐僑','宋','宋诗','song-poetry','','[]','常自在，常自在，莫受物觸隨變改。',212,'全唐诗/poet.song.178000.json','["常自在，常自在，莫受物觸隨變改。", "心常澄太虛，胸常涵滄海。", "志常明秋霜，氣常融春靄。", "常自在，常自在，莫或欺心旋遮蓋。", "此心常與天地通，日月神明環內外。", "萬物森森在吾下，我自小之自傷害。", "常自在，常自在，詩書樂處安精神。", "道義合時行身世，貧何足嗟，賤何□嘅，富何足淫，貴何足泰。", "靜惟飭身而無愧，動惟利□而盡愛。", "常自在，常自在，此外何求哉。", "有時詩一篇，有時酒一杯。", "庭花野草爲賓友，清風明月相追陪。", "陶吾真兮適吾性，常自在。", "常自在，何處有愁來。"]'),
('bf74ac5c-ff43-4ed8-a47c-21e9f9bd481f','次陳和仲惠雲山歌韵','徐僑','宋','宋诗','song-poetry','','[]','幽人尋坦道，爲言柔履剛。',164,'全唐诗/poet.song.178000.json','["幽人尋坦道，爲言柔履剛。", "所利在艱正，未取馬逐良。", "雲山坐深窈，無人蘭自芳。", "青青松與竹，障暑拒雪霜。", "人跡所罕到，亶爲煙雲鄉。", "老我志彫落，髮蒼而視茫。", "懷哉此丘壑，閑蹤寄忀徉。", "人事輒往復，世慮忘暄涼。", "書數種，琴一張，竹布充野服，筇杖替游韁。", "生來坦率得自遂，客至嘲誚庸何傷。", "非故逃名甘寂寂，攻嫌助長病茫茫。", "君詩明澹起予意，留取伴我山中藏。"]'),
('3742edd8-930f-4328-a588-e95eb9dfd74c','鶑兮歌','徐僑','宋','宋诗','song-poetry','','[]','鶑兮鶑兮載好音，羽毛自珍兮藏山林。',83,'全唐诗/poet.song.178000.json','["鶑兮鶑兮載好音，羽毛自珍兮藏山林。", "春出依柳兮秋隠林深，丘隅有木兮游知所止。", "睍睆求友兮期遠匪比，出處有度兮觀者爲儀。", "溫乎其聲和兮，聽者心夷。", "鶑兮□其禽乎，其禽之君子歟。"]'),
('b46f8cb3-0494-40ed-944d-c0f811a16247','燕兮歌','徐僑','宋','宋诗','song-poetry','','[]','燕兮燕兮，頡頏于飛。',83,'全唐诗/poet.song.178000.json','["燕兮燕兮，頡頏于飛。", "語呢喃兮聲哲支，居慕賢兮身緇衣。", "高明依棲兮王謝儕其主，去來有節兮春秋兮其旅。", "良時賡歌兮對爾吟哦，清燕論文兮聆爾話語。", "燕兮燕兮其禽乎，其禽之嘉賓歟。"]'),
('c95308b0-af00-4763-9e4e-1574c0f21f78','樵夫行','徐僑','宋','宋诗','song-poetry','','[]','晨征已輸行者早，紛來歛避樵夫道。',272,'全唐诗/poet.song.178000.json','["晨征已輸行者早，紛來歛避樵夫道。", "樵夫辛苦刈樵歸，昏莫結束更起炊。", "夜半出門星月暗，崎嶇露草寒濡衣。", "入市博得升合糧，歸來分與妻兒嘗。", "依前剝剝上山去，不住朝朝莫莫忙。", "樵夫樵夫休懊惱，世路艱難勤亦好。", "蝗蟲四起米價高，憐汝饑勞我未飽。", "我苦閑愁雪滿顛，烹葵煮藜過年年。", "夜枕欹傾半眠醒，或起浩歎窺星天。", "逢人說事只憂國，長哀無告窮已極。", "天下奸弊紛如麻，虎狼搏攫殫麋麚。", "愁眠忍餓不敢出，羸瘠膏髓堪推撾。", "冤氣干天天垂災，連年禾稼同枯荄。", "斯人每恨不速死，樵夫縱苦未及此。", "安得人仁公且剛，一掃蠆螫完民瘡。", "感動和氣時覆斗，樵夫飽食我醉酒。", "待與樵夫齊高歌，昔談王道今如何。"]'),
('c3ca1969-f249-4ff9-bd33-198049dd6ae5','舟溪吟','徐僑','宋','宋诗','song-poetry','','[]','舟溪羣山俱有情，禺昂環列如逢迎。',128,'全唐诗/poet.song.178000.json','["舟溪羣山俱有情，禺昂環列如逢迎。", "東出雙秀高沖天，推先兩峰當我前。", "二水南來炯相顧，合流于西疑欲住。", "成此溪山一段清，中有一園十畝平。", "著我翛然數間屋，遶屋但栽竹與菊。", "扶杖行舒景物娛，開卷坐對聖賢讀。", "嗟余藐焉天地間，居然分得此清閑。", "毋餒浩然有以老，也應不負爾溪山。"]'),
('6081598b-6a1b-4a9b-aecf-c84b593b283b','和邵康節蒼蒼吟','徐僑','宋','宋诗','song-poetry','','[]','穹窿奠計幾層蒼，繚遶難輸九曲腸。',96,'全唐诗/poet.song.178000.json','["穹窿奠計幾層蒼，繚遶難輸九曲腸。", "七曜運空機不斷，百川流下礙無妨。", "千林松柏獨堅正，一草薰蕕異臭香。", "祥戾毛羣若麟獍，愛憎羽族類鴞凰。", "最宜春風與秋月，忽作冬雷或夏霜。", "萬變雜興雖錯糅，一元不動固安詳。"]'),
('73193e3c-9efb-40b0-bb9b-cb93afee0c95','張家渡買魚','徐僑','宋','宋诗','song-poetry','','[]','北堂老人性嗜魚，有魚一飯空無餘。',192,'全唐诗/poet.song.178000.json','["北堂老人性嗜魚，有魚一飯空無餘。", "行水登舟喜動色，幾月乃得三四食。", "溪涸舟膠挽不去，舍舟行行溪上路。", "路入茅舍惟一翁，網挂壁頭兒負舂。", "問之有底不出漁，水動魚藏溪作風。", "强之不能許觴醪，翁爲持網兒持篙。", "挾艇過臨叢藻岸，踏竹下網屢成漫。", "忽然得鯉僅如掌，翁笑官有福可仗。", "我舟猶在極目涯，乃坐其艇與之往。", "烹魚一開慈顔驩，膠舟旋亦辭涸灘。", "兩日舟移無十里，吁嗟有此行路難。", "漁翁飲酒得錢去，一葉如飛烟水暮。"]'),
('271a7b26-6de9-413f-9469-e43a72a89956','送施持正司理解官','徐僑','宋','宋诗','song-poetry','','[]','人生會合難，四海皆兄弟。',288,'全唐诗/poet.song.178000.json','["人生會合難，四海皆兄弟。", "解后若爲寮，爲情乃其至。", "嚴陵雖陋邦，山水固佳致。", "宦遊於其間，亦未爲失計。", "嗟嗟我輩人，志不在名利。", "所趨必踏正，所論必根義。", "聖門有格言，胡不慥慥爾。", "險夷融一心，相與共守此。", "維君更直諒，多聞且知禮。", "責善有忠告，規失無因避。", "人或苦難合，我匪以爲具。", "始如石落落，終似旂旎旎。", "入議必追聯，出遊必連軌。", "朝夕恃驩比，同襟能有幾。", "君今先我去，落漠將何委。", "政此黯銷魂，臨分不我鄙。", "絕無兒女悲，慨慷及治己。", "竊聞之先儒，物我均一理。", "達人宏大觀，曲士局偏倚。", "偏倚狹一隅，愛惡無公是。", "大觀歸衆善，寬平有餘地。", "理義固無窮，虛心知所止。", "感君謙自牧，使我愁翻喜。", "還以作贈言，相觀要終始。"]'),
('26b4bc19-54fd-473d-b369-352b89d1fdd5','喜得孫','徐僑','宋','宋诗','song-poetry','','[]','我五十有四，纔今見其孫。',180,'全唐诗/poet.song.178000.json','["我五十有四，纔今見其孫。", "汝父亦三十，得子爲之昆。", "人生百年間，欻如駒隙奔。", "其間欣與戚，短長未暇論。", "長長與幼幼，一家團春溫。", "豈惟情愛足，是有禮義存。", "嗟我生苦晚，陟岵悲蚤吞。", "有懷當世憂，拙迂不自軒。", "老矣絕他念，先志惟所□。", "詩書茂花實，忠厚豐本根。", "要令汝輩長，續續熟予言。", "功名身外物，孝悌德之源。", "莫先家人正，所貴椒聊蕃。", "今朝情陪喜，添汝壯吾門。", "相與紹清白，無慚故丘園。"]'),
('57d4f7a6-106f-41f3-9239-7b1a7f5c93c4','雙松亭','徐僑','宋','宋诗','song-poetry','','[]','雙松如老虬，拜然俯於地。',120,'全唐诗/poet.song.178000.json','["雙松如老虬，拜然俯於地。", "山下草細微，降從所非類。", "昂藏烈丈夫，肯與樵牧比。", "樛枝若欲頹，直幹固不倚。", "外柔內則剛，物耳寓此理。", "吾觀世俗流，隨人盡棄己。", "此松乃不然，自下弗爲恥。", "所立峭已高，其節凜不記。", "滿眼春風生，中有歲寒意。", "敢告行道人，視此知所止。"]'),
('68a5a21b-f754-44d4-a433-759db5761f14','滕丞洎沖天觀先以詩來次韵謝之','徐僑','宋','宋诗','song-poetry','','["\u897f\u6e56"]','我本山林人，出處無意固。',228,'全唐诗/poet.song.178000.json','["我本山林人，出處無意固。", "君亦如山泉，隨地爲流注。", "方其居山時，文豹隠冥霧。", "又如出岫雲，散漫欻無據。", "憶昨我與君，相逢同一處。", "時時湖光亭，襟抱一披露。", "君橫膝上琴，我踵戶外屨。", "梅花落園春，辭君一朝去。", "詩筒遽寥寥，粵從浙濡渡。", "雁去燕復來，不得一字附。", "撫懷興長嗟，恍然此散聚。", "何期老鶴臞，短翮忽舒布。", "九皋聳孤唳，羣仙翕清譽。", "高寒玉峰巔，爲爾肯一駐。", "杭嚴兩西湖，未必置愛惡。", "瞥從子陵臺，來踏蘇公路。", "山友而水賓，風曉而煙暮。", "行止初何心，同是一真趣。", "願於人海中，更覓山中句。"]'),
('af951474-fa19-4b55-977e-74e4bd1591ce','同官三人率慶裘元量司直於湖中有詩呈諸公','徐僑','宋','宋诗','song-poetry','','[]','欲晴未晴還不雨，無日無風又無暑。',128,'全唐诗/poet.song.178000.json','["欲晴未晴還不雨，無日無風又無暑。", "煙薄微籠四岸山，空翠却向湖中聚。", "今日之游誠佳哉，湖山文字中銜盃。", "相爲此約亦已久，天相其逢資追陪。", "吾儕官閑無一事，平生丘壑詎輕棄。", "相從於此合鍾情，無奈同襟欲分袂。", "西風著意向芙蓉，綠柳未疎花正濃。", "勸君慢理江頭楫，更作一日來從容。"]'),
('5b5fc592-b489-457f-8424-3df637479f55','永樂道中','徐僑','宋','宋诗','song-poetry','','[]','夫物有奇觀，而於天地間。',48,'全唐诗/poet.song.178000.json','["夫物有奇觀，而於天地間。", "月中浮白水，雨後對青山。", "雲巘泉千尺，雪天梅一班。", "有時逢此景，清興頗相關。"]'),
('696e32da-6b66-4130-8137-e8a4eabb1a1a','即事','徐僑','宋','宋诗','song-poetry','','[]','在家貧亦好，居官貧更宜。',48,'全唐诗/poet.song.178000.json','["在家貧亦好，居官貧更宜。", "布被不妨溫，菜羹有餘滋。", "客至草具杯，事閑遣興詩。", "外此了無撓，澹然心地夷。"]'),
('e6863deb-d136-442a-8564-79a8670e0e15','初晴出南山過西湖往九峰復飲於湖光','徐僑','宋','宋诗','song-poetry','','["\u897f\u6e56"]','積雨鬰愁思，初日破春泥。',48,'全唐诗/poet.song.178000.json','["積雨鬰愁思，初日破春泥。", "勝處欲何往，游情翻自迷。", "柳招追綠渡，梅引逐香蹊。", "却憶杜陵老，慇懃出碧雞。"]'),
('6e77f493-54fc-4d8d-80c8-6b1c58c47345','青田舟中','徐僑','宋','宋诗','song-poetry','','[]','睡起愁無緒，持書復懶披。',48,'全唐诗/poet.song.178000.json','["睡起愁無緒，持書復懶披。", "篷嫌斜日照，襟愜好風吹。", "水闊舟移細，山長鳥去遲。", "悠悠天外意，惟只寸心知。"]'),
('394725ec-d45b-45b9-8872-6b59fb3392e2','殿廬考試畢','徐僑','宋','宋诗','song-poetry','','[]','地禁塵難到，亭深暑不奸。',48,'全唐诗/poet.song.178000.json','["地禁塵難到，亭深暑不奸。", "一杯天上把，千策日邊看。", "頻勞君恩重，危言士志殫。", "治安渾道未，臣亦欲披肝。"]'),
('7f83bf5a-36ea-497f-b010-a33bdc812f36','送真景元直院將漕江東  其一','徐僑','宋','宋诗','song-poetry','','[]','識度追諸老，文章用一班。',48,'全唐诗/poet.song.178000.json','["識度追諸老，文章用一班。", "志心深國計，正論豫時艱。", "將指顧憂地，登車慷慨間。", "却聞塗巷語，有詔命公還。"]'),
('38264547-d851-48ca-88fb-04ccd625cda9','送真景元直院將漕江東  其二','徐僑','宋','宋诗','song-poetry','','[]','憂國誠如此，憂民事可知。',48,'全唐诗/poet.song.178000.json','["憂國誠如此，憂民事可知。", "政苛紛蠹螫，官墨厭膏脂。", "誰謂長城在，不扶元氣衰。", "天顔還咫尺，時聽遠猷馳。"]'),
('652bb104-46af-41c6-9737-4513c38efdf0','送李夢間赴浙東倉','徐僑','宋','宋诗','song-poetry','','[]','帝遣軺車重，深懷浙水東。',48,'全唐诗/poet.song.178000.json','["帝遣軺車重，深懷浙水東。", "幽崖須烈日，寒谷倚春風。", "惠達摧姦裏，功浮按職中。", "活人千百萬，歸報□□宮。"]'),
('63bb57ed-dd8a-4baa-8ea5-d37b652894fb','送葉知道歸永嘉約其再爲歷陽來','徐僑','宋','宋诗','song-poetry','','[]','心事相知久，交情一見真。',48,'全唐诗/poet.song.178000.json','["心事相知久，交情一見真。", "靜參師友正，細語弟兄親。", "索去銷魂惡，期來刮眼新。", "臨分不多語，重會莫過□。"]'),
('57c15f08-01e2-4117-aa00-0c5583e54eea','看栽菊','徐僑','宋','宋诗','song-poetry','','[]','我生隨所止，唯種竹與菊。',48,'全唐诗/poet.song.178000.json','["我生隨所止，唯種竹與菊。", "菊靚而無華，竹清而不俗。", "淵明興悠然，子猷愛之酷。", "夫我乃兼之，佳趣於爾足。"]'),
('fa59ba32-9286-472d-a12c-034049b7184e','即事','徐僑','宋','宋诗','song-poetry','','[]','白墁蠲敗壁，墨燼沃塵楹。',48,'全唐诗/poet.song.178000.json','["白墁蠲敗壁，墨燼沃塵楹。", "瓦闕刪茅補，牆穿埏土平。", "竹栽簷外箇，花植盎中莖。", "次第成吾趣，婆娑樂此生。"]'),
('e12fb8b3-8d80-4350-bce0-44d5ec07c9d2','書齋即事','徐僑','宋','宋诗','song-poetry','','[]','塵世燈窗外，寒儒竹簡情。',48,'全唐诗/poet.song.178000.json','["塵世燈窗外，寒儒竹簡情。", "三杯慰岑寂，一榻寄孤清。", "夜永那能睡，天寒不肯明。", "起來重搔首，江海一鷗輕。"]'),
('352413b4-8f38-498a-aada-83fa49925173','西軒臘梅','徐僑','宋','宋诗','song-poetry','','[]','花開何太晚，頼爾張簷楹。',48,'全唐诗/poet.song.178000.json','["花開何太晚，頼爾張簷楹。", "春後幾多日，枝頭三四英。", "人嫌芳意懶，我愛澹標清。", "恰好來深夜，移牀對月明。"]'),
('25612293-5028-4d32-8fc5-2096ce5366d2','竹布道服','徐僑','宋','宋诗','song-poetry','','[]','智創輕我節，工閑妙出機。',48,'全唐诗/poet.song.178000.json','["智創輕我節，工閑妙出機。", "疏風寧事扇，被體若無衣。", "頗與山翁稱，何嫌俗子譏。", "此君元我契，相與不相違。"]'),
('7dfdb105-67c5-4264-9b5a-ec783017ccb3','即事','徐僑','宋','宋诗','song-poetry','','[]','關吾朝夕事，月嶺與雲岑。',48,'全唐诗/poet.song.178000.json','["關吾朝夕事，月嶺與雲岑。", "坐冊澹中味，行筇老者襟。", "酒隨深淺酌，詩任短長吟。", "時與七賢語，知音在素琴。"]'),
('91e3a9b0-d64e-4da6-8644-c62d9a3d3abd','道中口占呈能之','徐僑','宋','宋诗','song-poetry','','[]','闕然不見懷千慮，特地相過無一言。',64,'全唐诗/poet.song.178000.json','["闕然不見懷千慮，特地相過無一言。", "平日交情如水淡，暫時客裏似春溫。", "酒隨深淺有餘味，事向細微無不論。", "漫道與君心莫逆，誰知樸直箇中存。"]'),
('963209a2-9086-4609-b4cb-8d3db17d15a8','鑑湖','徐僑','宋','宋诗','song-poetry','','[]','箇中巖壑欠相羊，秋色無邊古興長。',64,'全唐诗/poet.song.178000.json','["箇中巖壑欠相羊，秋色無邊古興長。", "寒盡鑑湖僅荷浦，靈遺禹廟尚梅梁。", "追尋遊舫空千載，物色先賢但一堂。", "征□倚風歸路晚，可堪晴月照凄涼。"]'),
('74da43a7-0542-4be4-b1fc-a953ce0438bb','得嚴陵推官','徐僑','宋','宋诗','song-poetry','','[]','擬乞四明幕下客，忽得嚴陵闕兩年。',64,'全唐诗/poet.song.178000.json','["擬乞四明幕下客，忽得嚴陵闕兩年。", "造物故憐貧已甚，去家不費一篙船。", "世事低昂吾有分，人生出處亦關天。", "釣臺高士不可尚，贏得桐江在眼前。"]'),
('ff811dd0-a7ea-4159-a91f-26e781cd316b','和滕丞元秀韵','徐僑','宋','宋诗','song-poetry','','[]','秋期載酒子雲居，春柳還驚綠映渠。',64,'全唐诗/poet.song.178000.json','["秋期載酒子雲居，春柳還驚綠映渠。", "幾欲出門阻風雨，半因居幕困文書。", "自違清隠三時久，空擬憂懷一日舒。", "想見湖邊嘗獨立，不禁鷗鷺問何如。"]'),
('cd69c6a7-9bb2-4e9e-9a83-3be5664603ef','和呂巽伯韵','徐僑','宋','宋诗','song-poetry','','[]','何事貪乘逆水船，此心長向白雲邊。',64,'全唐诗/poet.song.178000.json','["何事貪乘逆水船，此心長向白雲邊。", "琴書篷底一樽酒，花柳江頭三月天。", "逸興只將詩句遣，清襟那就俗塵牽。", "簿書不到斑衣底，進學輸君屬壯年。"]'),
('46adf11d-476e-49dd-9ffe-298ba5e265dc','喻叔厚總幹寄詩甚富','徐僑','宋','宋诗','song-poetry','','[]','從君把酒爐峰下，去踏黄塵三見秋。',64,'全唐诗/poet.song.178000.json','["從君把酒爐峰下，去踏黄塵三見秋。", "別後便教詩社冷，夢中尤憶草堂幽。", "忽承珠玉聯佳什，賸喜亭池添勝遊。", "最想版輿頻御處，山花庭草總忘憂。"]'),
('c8f63573-ffc5-4469-a7ec-00288c53d6d9','安溪','徐僑','宋','宋诗','song-poetry','','[]','潮回盡處曉江清，百丈灘頭舟子情。',64,'全唐诗/poet.song.178000.json','["潮回盡處曉江清，百丈灘頭舟子情。", "饒我靜觀黄卷罷，爲渠卧看白雲輕。", "炫蓬滉漾龍蛇影，喧枕蕭騷風雨聲。", "無限青山飽秋色，去來誰暇與將迎。"]'),
('11ab2d15-006d-4c4a-81c7-eedc3e1e6fb8','司戶攝淳安丞同官送至西湖支使有詩因次韵','徐僑','宋','宋诗','song-poetry','','["\u897f\u6e56"]','把酒湖亭一笑逢，沿湖猶擁綠叢叢。',64,'全唐诗/poet.song.178000.json','["把酒湖亭一笑逢，沿湖猶擁綠叢叢。", "倒涵嵐影晴煙紫，回射城陰夕照紅。", "愁緒不關歌舞外，交情却在別離中。", "片帆我亦隨西下，小□凭欄蔌蔌風。"]'),
('906c142a-f15e-4eb2-add8-5a3558dbfc50','久不作詩立春以詩并酒送滕知丞','徐僑','宋','宋诗','song-poetry','','[]','羨君蕭散脫塵□，別□□官自不卑。',64,'全唐诗/poet.song.178000.json','["羨君蕭散脫塵□，別□□官自不卑。", "判斷湖山詩有按，追呼風月酒隨司。", "衙官宋玉供奔走，從事青州奉指麾。", "慚我真成今俗吏，固應期會絕文移。"]'),
('7c76519b-b9a0-4fab-b959-d606ca6040bf','因報謁過西湖','徐僑','宋','宋诗','song-poetry','','["\u897f\u6e56"]','不見西湖兩鬢絲，湖光如舊不□欺。',64,'全唐诗/poet.song.178000.json','["不見西湖兩鬢絲，湖光如舊不□欺。", "畫橋各領遊船去，密港誰知漁艇移。", "綠柳行疎人步隠，翠荷叢淺鳥飛遲。", "清風汗漫知何許，小憇招提獨自移。"]'),
('5890a84a-7515-4616-8dc2-4805232ba86f','次韵謝滕丞惠詩','徐僑','宋','宋诗','song-poetry','','[]','一從驅迫入通闤，望渺江湖夢遶山。',64,'全唐诗/poet.song.178000.json','["一從驅迫入通闤，望渺江湖夢遶山。", "日墮紅塵轉湮沒，天教羣玉與躋攀。", "莫孤文字澹中趣，要識人情奔處間。", "多謝故人相警發，驪珠特地出滄灣。"]'),
('82d61a4d-deaa-4026-9a24-8dbf3f1c5bf8','次韵能之賀除','徐僑','宋','宋诗','song-poetry','','[]','初無家學贍三餘，濫被君恩有此除。',64,'全唐诗/poet.song.178000.json','["初無家學贍三餘，濫被君恩有此除。", "非取金華能占對，但令東觀與觀書。", "汗顔莫稱英髦選，冷眼終輸山澤居。", "自昔與君憂世切，只今何策塞侵漁。"]'),
('9b82c7cd-62ed-45b1-b015-596d9bb2d7a6','寄題趙仁父兩山堂','徐僑','宋','宋诗','song-poetry','','[]','兩山對立著君三，山意無窮勿浪參。',64,'全唐诗/poet.song.178000.json','["兩山對立著君三，山意無窮勿浪參。", "靜底規摹隨處有，忙時事業箇中涵。", "移文肯爲輕離北，采菊何嘗索見南。", "會取孔門仁者意，等閑風月不虛談。"]'),
('10a8328f-97de-4e2f-9776-b7ba4b72b81e','和杜叔高相約湖上韵','徐僑','宋','宋诗','song-poetry','','[]','湖上朝市兩忘言，勝趣何須頻出門。',64,'全唐诗/poet.song.178000.json','["湖上朝市兩忘言，勝趣何須頻出門。", "要並雪巖尋酒伴，更從梅隠覓詩魂。", "風低雁溆數行影，烟障鳬波幾疊痕。", "此意古來誰領得，可無同調與同論。"]'),
('ca16e9b0-864c-412d-819e-860ddd5ad7f5','能之寄詩和其月夜泛舟韵以寓相思','徐僑','宋','宋诗','song-poetry','','[]','別時來悟合并難，君向湖山去不還。',64,'全唐诗/poet.song.178000.json','["別時來悟合并難，君向湖山去不還。", "好語欲酬嗟侶少，空餐亡補媿官閑。", "身謀未肯忘箕潁，世慮無嫌付觸蠻。", "幸有孤山陳迹在，倘來同踏石苔斑。"]'),
('9eee5776-4bbd-4947-8b00-f5b17b1a94b1','韓退之藍田丞廳記所謂鴈鶩者相承以爲吏每切不然往往人未之信偶讀吳子寬詩有鴈鶩庭空之語因作此云','徐僑','宋','宋诗','song-poetry','','[]','退之作文自天巧，讀者未免加人私。',64,'全唐诗/poet.song.178000.json','["退之作文自天巧，讀者未免加人私。", "紙尾連銜行鴈鶩，同僚翻作刻木期。", "句讀中分肯趣短，一輩抱睨何多爲。", "自唐及今襲訛舛，文公有神應點嗤。"]'),
('8fab0002-13f7-4853-a62b-3b7e2c70cc44','晨興耕菴','徐僑','宋','宋诗','song-poetry','','[]','往來烏兔底匆忙，老去身心只自將。',64,'全唐诗/poet.song.178000.json','["往來烏兔底匆忙，老去身心只自將。", "理櫛不勝渾種種，繙書未了苦忙忙。", "情知世俗風光淺，日覺山林氣味長。", "有負夙心依屺岵，更將餘力事松篁。"]'),
('9411b747-9187-4f98-afb2-416b4203162a','毅齋即事','徐僑','宋','宋诗','song-poetry','','[]','自吾齋外付諸兒，除却詩書總不知。',64,'全唐诗/poet.song.178000.json','["自吾齋外付諸兒，除却詩書總不知。", "苔色上侵閑坐處，鳥聲來和獨吟時。", "十分秋氣重陽近，一味天涼老者宜。", "調得身心能自慊，止吾所止復何疑。"]'),
('3f3debba-1893-41c6-97fc-61bd85c16963','重陽後二日','徐僑','宋','宋诗','song-poetry','','[]','我來不及赴重陽，孤負清幽獨自芳。',64,'全唐诗/poet.song.178000.json','["我來不及赴重陽，孤負清幽獨自芳。", "夾徑也能隨意白，出牆無柰著情黄。", "亟邀舊友將余玩，細酌新醪對汝嘗。", "懸知靖節無人見，却見南山此意長。"]'),
('4a475fbf-c96d-4c96-951c-7f00aea53096','讀藝文志','徐僑','宋','宋诗','song-poetry','','[]','所存諸子少知名，自古陳編浩莫程。',64,'全唐诗/poet.song.178000.json','["所存諸子少知名，自古陳編浩莫程。", "未說合神老成子，誰傳談易杜田生。", "到頭法語那能廢，終久浮言自不行。", "只向孔門詳答問，正塗坦坦甚分明。"]'),
('e1cdc6e3-e2cb-487c-9134-8d88e8d67b57','詠拳石菖蒲','徐僑','宋','宋诗','song-poetry','','[]','巖泉潠洒著根纖，拳石相依自糾纏。',64,'全唐诗/poet.song.178000.json','["巖泉潠洒著根纖，拳石相依自糾纏。", "土葉漸除青带冗，細莖初發綠毛鮮。", "一塵不許溷幽雅，百草誰能並潔娟。", "日課蒼頭注新汲，要移林壑在庭前。"]'),
('6174b29f-9dab-4651-bda9-137a499a6797','五雲寺','徐僑','宋','宋诗','song-poetry','','[]','黄雲不似五雲深，隠隠回環坐此林。',64,'全唐诗/poet.song.178000.json','["黄雲不似五雲深，隠隠回環坐此林。", "巒阜幾重遮入路，隴岡百里護來峰。", "單僧憐汝喧魚板，漫叟便余玩鶴琴。", "茶罷策筇無箇事，登高時復一長吟。"]'),
('89ecc3d5-6a0b-4f7b-b59c-f9bbc0230029','後坡','徐僑','宋','宋诗','song-poetry','','[]','扶筇剝啄一山中，幽興偏於此處濃。',64,'全唐诗/poet.song.178000.json','["扶筇剝啄一山中，幽興偏於此處濃。", "前屏樹柯呈列岫，旁開林隙出奇峰。", "座迎夜月分吾石，欄度朝雲對汝松。", "俗客不來人籟寂，省心時聽數聲鐘。"]'),
('712c85f8-5239-4f7b-812c-1c6dff8d41f8','近陳和仲訪山間不值留詩今次韵招之','徐僑','宋','宋诗','song-poetry','','[]','寄跡雲山澹澹心，舊盟得得荷君尋。',64,'全唐诗/poet.song.178000.json','["寄跡雲山澹澹心，舊盟得得荷君尋。", "偶緣他客追遊屐，却使良朋誤盍簪。", "政苦寒飈妨剝□，□□□□□□□。", "□□□□□□□，□□□□□□□。"]'),
('a339cb17-d38a-4c96-ab3b-7eaf90f61a31','宿野墅五更窗月照瓶中老梅清甚有感','徐僑','宋','宋诗','song-poetry','','[]','桃李紛紛一餉花，風清月白老生涯。',64,'全唐诗/poet.song.178000.json','["桃李紛紛一餉花，風清月白老生涯。", "取之無盡山林藏，求而有餘農圃家。", "游是理中無愧慊，樂吾心處是榮華。", "較他絃管淒涼地，巵酒杯羹總自奢。"]');
